{
  const S = ["chain-rule"];
  const mcq: MCQ[] = [
    { content: "The derivative of $y = (2x + 1)^3$ is:", optionA: "$3(2x+1)^2$", optionB: "$6(2x+1)^2$", optionC: "$3(2x+1)^2 \\cdot 2x$", optionD: "$2(2x+1)^2$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Let $u = 2x + 1$. Then $\\dfrac{dy}{dx} = 3u^2 \\cdot \\dfrac{du}{dx} = 3(2x+1)^2 \\cdot 2 = 6(2x+1)^2$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The derivative of $y = e^{3x}$ is:", optionA: "$e^{3x}$", optionB: "$3e^{3x}$", optionC: "$3x e^{3x-1}$", optionD: "$e^{3x}/3$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** By the chain rule with $u = 3x$, $\\dfrac{dy}{dx} = e^{3x} \\cdot 3 = 3e^{3x}$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The derivative of $y = \\sin(2x)$ is:", optionA: "$\\cos(2x)$", optionB: "$2\\cos(2x)$", optionC: "$-2\\sin(2x)$", optionD: "$2\\sin(2x)$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Chain rule: $\\dfrac{d}{dx}\\sin(u) = \\cos(u) \\cdot \\dfrac{du}{dx}$ with $u = 2x$.\n\n$$\\dfrac{dy}{dx} = 2\\cos(2x).$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The derivative of $y = \\ln(5x)$ (for $x > 0$) is:", optionA: "$\\dfrac{1}{5x}$", optionB: "$\\dfrac{5}{x}$", optionC: "$\\dfrac{1}{x}$", optionD: "$5\\ln x$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Chain rule: $\\dfrac{1}{5x} \\cdot 5 = \\dfrac{1}{x}$. (Alternatively, $\\ln(5x) = \\ln 5 + \\ln x$, derivative is $1/x$.)\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The derivative of $y = \\cos(4x)$ is:", optionA: "$4\\sin(4x)$", optionB: "$-\\sin(4x)$", optionC: "$-4\\sin(4x)$", optionD: "$4\\cos(4x)$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Chain rule with $u = 4x$.\n\n$$\\dfrac{dy}{dx} = -\\sin(4x) \\cdot 4 = -4\\sin(4x).$$\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The derivative of $y = \\sqrt{x^2 + 1}$ is:", optionA: "$\\dfrac{x}{\\sqrt{x^2+1}}$", optionB: "$\\dfrac{1}{2\\sqrt{x^2+1}}$", optionC: "$\\dfrac{2x}{\\sqrt{x^2+1}}$", optionD: "$\\dfrac{1}{\\sqrt{x^2+1}}$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Let $u = x^2 + 1$. Then $y = u^{1/2}$.\n\n$$\\dfrac{dy}{dx} = \\tfrac{1}{2} u^{-1/2} \\cdot 2x = \\dfrac{x}{\\sqrt{x^2+1}}.$$\n\n**Answer: A**", subtopicSlugs: S },
    // Medium
    { content: "The derivative of $y = e^{x^2}$ is:", optionA: "$e^{x^2}$", optionB: "$2x e^{x^2}$", optionC: "$x^2 e^{x^2}$", optionD: "$e^{2x}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Chain rule: let $u = x^2$, so $\\dfrac{du}{dx} = 2x$.\n\n$$\\dfrac{dy}{dx} = e^{x^2} \\cdot 2x = 2x e^{x^2}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f(x) = (3x^2 + 1)^4$, then $f'(x)$ equals:", optionA: "$4(3x^2+1)^3$", optionB: "$24x(3x^2+1)^3$", optionC: "$6x(3x^2+1)^3$", optionD: "$12x(3x^2+1)^3$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Chain rule with $u = 3x^2 + 1$, $\\dfrac{du}{dx} = 6x$.\n\n$$f'(x) = 4(3x^2+1)^3 \\cdot 6x = 24x(3x^2+1)^3.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The derivative of $y = \\ln(x^2 + 4)$ is:", optionA: "$\\dfrac{1}{x^2+4}$", optionB: "$\\dfrac{2x}{x^2+4}$", optionC: "$\\dfrac{2}{x}$", optionD: "$\\dfrac{x}{x^2+4}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Chain rule: $\\dfrac{1}{u} \\cdot \\dfrac{du}{dx}$ where $u = x^2 + 4$.\n\n$$\\dfrac{dy}{dx} = \\dfrac{2x}{x^2+4}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The derivative of $y = \\sin(x^2)$ is:", optionA: "$\\cos(x^2)$", optionB: "$2x \\cos(x^2)$", optionC: "$2 \\cos(x^2)$", optionD: "$-\\cos(x^2) \\cdot 2x$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Let $u = x^2$, $\\dfrac{du}{dx} = 2x$.\n\n$$\\dfrac{dy}{dx} = \\cos(x^2) \\cdot 2x = 2x\\cos(x^2).$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: `The curve $y = e^{-x^2}$ is shown.\n\n${graphImage((x) => Math.exp(-x * x), { xMin: -3, xMax: 3, yMin: -0.5, yMax: 1.5, marks: [{ x: 0, y: 1, label: "(0,1)" }] }, "Graph y=e^{-x^2}")}\n\nAt the origin, $\\dfrac{dy}{dx}$ equals:`, optionA: "$-2$", optionB: "$0$", optionC: "$1$", optionD: "$-1$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\dfrac{dy}{dx} = e^{-x^2} \\cdot (-2x)$. At $x = 0$, this is $0$ — horizontal tangent at the peak.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f(x) = \\cos(3x + \\pi)$, then $f'(x)$ equals:", optionA: "$-\\sin(3x+\\pi)$", optionB: "$3\\sin(3x+\\pi)$", optionC: "$-3\\sin(3x+\\pi)$", optionD: "$-3\\cos(3x+\\pi)$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Chain rule: $-\\sin(3x+\\pi) \\cdot 3 = -3\\sin(3x+\\pi)$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The derivative of $y = (1 - x)^5$ is:", optionA: "$5(1-x)^4$", optionB: "$-5(1-x)^4$", optionC: "$5x(1-x)^4$", optionD: "$(1-x)^4$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Chain rule: $5(1-x)^4 \\cdot (-1) = -5(1-x)^4$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: `The function values below are for $f(x) = \\sin(2x)$.\n\n| $x$ | $0$ | $\\pi/4$ | $\\pi/2$ | $3\\pi/4$ | $\\pi$ |\n|---|---|---|---|---|---|\n| $f(x)$ | $0$ | $1$ | $0$ | $-1$ | $0$ |\n\nThe value of $f'(0)$ is:`, optionA: "$0$", optionB: "$1$", optionC: "$2$", optionD: "$-2$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = 2\\cos(2x)$, so $f'(0) = 2\\cos 0 = 2$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The derivative of $y = e^{\\sin x}$ is:", optionA: "$e^{\\sin x}$", optionB: "$\\cos x \\cdot e^{\\sin x}$", optionC: "$-\\sin x \\cdot e^{\\sin x}$", optionD: "$\\sin x \\cdot e^{\\cos x}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Chain rule: $e^{\\sin x} \\cdot \\cos x$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Let $y = \\ln(\\cos x)$, where $\\cos x > 0$. Then $\\dfrac{dy}{dx}$ equals:", optionA: "$-\\tan x$", optionB: "$\\tan x$", optionC: "$-\\sin x$", optionD: "$\\dfrac{1}{\\cos x}$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\dfrac{1}{\\cos x} \\cdot (-\\sin x) = -\\tan x$.\n\n**Answer: A**", subtopicSlugs: S },
    // Hard
    { content: "The derivative of $y = \\sin^2(x)$ is:", optionA: "$2\\sin x$", optionB: "$2\\sin x \\cos x$", optionC: "$\\cos^2 x$", optionD: "$-2\\sin x \\cos x$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Let $u = \\sin x$, so $y = u^2$. Then $\\dfrac{dy}{dx} = 2u \\cdot \\cos x = 2\\sin x \\cos x = \\sin(2x)$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f(x) = \\sqrt{1 - x^2}$ (for $-1 \\leq x \\leq 1$), then $f'\\!\\left(\\dfrac{1}{2}\\right)$ equals:", optionA: "$-\\dfrac{1}{\\sqrt{3}}$", optionB: "$-\\dfrac{1}{2\\sqrt{3}}$", optionC: "$\\dfrac{1}{\\sqrt{3}}$", optionD: "$-\\dfrac{\\sqrt{3}}{2}$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $f'(x) = \\dfrac{-2x}{2\\sqrt{1-x^2}} = \\dfrac{-x}{\\sqrt{1-x^2}}$.\n\nAt $x = 1/2$: $f'(1/2) = \\dfrac{-1/2}{\\sqrt{3/4}} = \\dfrac{-1/2}{\\sqrt{3}/2} = -\\dfrac{1}{\\sqrt{3}}$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The derivative of $y = e^{2\\ln x}$ (for $x > 0$) is:", optionA: "$2x$", optionB: "$2e^{2\\ln x}$", optionC: "$\\dfrac{2}{x}$", optionD: "$2\\ln x \\cdot e^{2\\ln x}$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Simplify first: $e^{2\\ln x} = e^{\\ln(x^2)} = x^2$, so $\\dfrac{dy}{dx} = 2x$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "A cube has volume $V(t) = (2 + t)^3$ cm$^3$ at time $t \\geq 0$ seconds. The rate of change of the side length with respect to time (in cm/s) is:", optionA: "$3$", optionB: "$1$", optionC: "$2 + t$", optionD: "$3(2+t)^2$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Side length $s(t) = V^{1/3} = 2 + t$, so $\\dfrac{ds}{dt} = 1$ cm/s.\n\n**Answer: B**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "Differentiate $y = (3x - 1)^4$ with respect to $x$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Apply the chain rule with $u = 3x - 1$.\n\n$$\\dfrac{dy}{dx} = 4(3x - 1)^3 \\cdot 3.$$\n\n**Step 2 (1 mark):** Simplify.\n\n$$\\dfrac{dy}{dx} = 12(3x - 1)^3.$$", subtopicSlugs: S },
    { content: "Find $\\dfrac{dy}{dx}$ if $y = e^{4x - 2}$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Chain rule with $u = 4x - 2$.\n\n$$\\dfrac{dy}{dx} = e^{4x - 2} \\cdot 4.$$\n\n**Step 2 (1 mark):** Write the result.\n\n$$\\dfrac{dy}{dx} = 4 e^{4x - 2}.$$", subtopicSlugs: S },
    { content: "Find the derivative of $y = \\cos(3x + 2)$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Chain rule with $u = 3x + 2$.\n\n$$\\dfrac{dy}{dx} = -\\sin(3x + 2) \\cdot 3.$$\n\n**Step 2 (1 mark):** Simplify.\n\n$$\\dfrac{dy}{dx} = -3\\sin(3x + 2).$$", subtopicSlugs: S },
    { content: "Differentiate $y = \\ln(2x^2 + 1)$.", marks: 2, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Chain rule: $\\dfrac{1}{u} \\cdot \\dfrac{du}{dx}$ where $u = 2x^2 + 1$.\n\n**Step 2 (1 mark):** Compute.\n\n$$\\dfrac{dy}{dx} = \\dfrac{4x}{2x^2 + 1}.$$", subtopicSlugs: S },
    { content: "Find $f'(x)$ when $f(x) = e^{x^3}$.", marks: 2, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Chain rule with $u = x^3$.\n\n$$f'(x) = e^{x^3} \\cdot 3x^2.$$\n\n**Step 2 (1 mark):** Write the result.\n\n$$f'(x) = 3x^2 e^{x^3}.$$", subtopicSlugs: S },
    { content: "Differentiate $y = \\sqrt{3x^2 - 5}$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Rewrite as $(3x^2 - 5)^{1/2}$.\n\n**Step 2 (1 mark):** Apply chain rule.\n\n$$\\dfrac{dy}{dx} = \\tfrac{1}{2}(3x^2 - 5)^{-1/2} \\cdot 6x.$$\n\n**Step 3 (1 mark):** Simplify.\n\n$$\\dfrac{dy}{dx} = \\dfrac{3x}{\\sqrt{3x^2 - 5}}.$$", subtopicSlugs: S },
    { content: "Find $\\dfrac{dy}{dx}$ for $y = \\sin^3(x)$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Rewrite: $y = (\\sin x)^3$.\n\n**Step 2 (1 mark):** Apply chain rule with $u = \\sin x$.\n\n$$\\dfrac{dy}{dx} = 3(\\sin x)^2 \\cdot \\cos x.$$\n\n**Step 3 (1 mark):** Simplify.\n\n$$\\dfrac{dy}{dx} = 3\\sin^2 x \\cos x.$$", subtopicSlugs: S },
    { content: "If $f(x) = e^{-3x^2}$, find $f'(x)$.", marks: 2, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Chain rule: $e^{-3x^2} \\cdot (-6x)$.\n\n**Step 2 (1 mark):** Simplify.\n\n$$f'(x) = -6x e^{-3x^2}.$$", subtopicSlugs: S },
    { content: "Let $y = \\cos(e^x)$. Find $\\dfrac{dy}{dx}$.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Let $u = e^x$, so $y = \\cos u$.\n\n**Step 2 (1 mark):** Apply chain rule.\n\n$$\\dfrac{dy}{dx} = -\\sin(e^x) \\cdot e^x.$$\n\n**Step 3 (1 mark):** Write final form.\n\n$$\\dfrac{dy}{dx} = -e^x \\sin(e^x).$$", subtopicSlugs: S },
    { content: "A particle's position is $s(t) = \\ln(t^2 + 1)$ metres at time $t \\geq 0$ seconds. Find its velocity at $t = 2$.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Velocity is $s'(t)$.\n\n**Step 2 (1 mark):** Apply chain rule.\n\n$$s'(t) = \\dfrac{2t}{t^2 + 1}.$$\n\n**Step 3 (1 mark):** Substitute $t = 2$.\n\n$$s'(2) = \\dfrac{4}{5}.$$\n\n**Step 4 (1 mark):** State units.\n\n$$v(2) = \\dfrac{4}{5} \\text{ m/s}.$$", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "Let $f(x) = (x^2 + 2)^3$.\n\n**a.** Find $f'(x)$ using the chain rule. (2 marks)\n\n**b.** Find the value of $f'(1)$. (2 marks)\n\n**c.** Find the equation of the tangent to $y = f(x)$ at $x = 1$. (3 marks)\n\n**d.** Find all values of $x$ for which $f'(x) = 0$. (2 marks)\n\n**e.** Explain why $f(x) \\geq 0$ for all real $x$. (2 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Let $u = x^2 + 2$, so $f = u^3$.\n\n*Step 2 (1 mark):* Chain rule gives\n\n$$f'(x) = 3(x^2 + 2)^2 \\cdot 2x = 6x(x^2 + 2)^2.$$\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Substitute $x = 1$.\n\n$$f'(1) = 6 \\cdot 1 \\cdot (1 + 2)^2.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$f'(1) = 6 \\cdot 9 = 54.$$\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Compute $f(1) = 3^3 = 27$.\n\n*Step 2 (1 mark):* Tangent form: $y - 27 = 54(x - 1)$.\n\n*Step 3 (1 mark):* Simplify.\n\n$$y = 54x - 27.$$\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Set $f'(x) = 6x(x^2 + 2)^2 = 0$.\n\n*Step 2 (1 mark):* Since $(x^2 + 2)^2 > 0$ always, $x = 0$ is the only solution.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Note $x^2 + 2 \\geq 2 > 0$.\n\n*Step 2 (1 mark):* Cube of a positive number is positive, so $f(x) = (x^2 + 2)^3 > 0$ for all real $x$.", subtopicSlugs: S },
    { content: "Let $f(x) = e^{2x - 1}$.\n\n**a.** Find $f'(x)$. (1 mark)\n\n**b.** Find $f'(0)$ and $f(0)$. (2 marks)\n\n**c.** Find the equation of the tangent to $y = f(x)$ at $x = 0$. (2 marks)\n\n**d.** Show that $f''(x) = 4 f(x)$. (2 marks)\n\n**e.** Solve $f'(x) = 2$. (2 marks)", marks: 9, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* Chain rule.\n\n$$f'(x) = 2e^{2x - 1}.$$\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $f(0) = e^{-1} = 1/e$.\n\n*Step 2 (1 mark):* $f'(0) = 2e^{-1} = 2/e$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Use point-gradient form.\n\n$$y - 1/e = (2/e)(x - 0).$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$y = \\dfrac{2x + 1}{e}.$$\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Differentiate $f'(x) = 2e^{2x-1}$ again.\n\n$$f''(x) = 4 e^{2x - 1}.$$\n\n*Step 2 (1 mark):* Compare: $4 e^{2x-1} = 4 f(x)$. ✓\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Set $2 e^{2x - 1} = 2$.\n\n$$e^{2x - 1} = 1.$$\n\n*Step 2 (1 mark):* Solve.\n\n$$2x - 1 = 0 \\implies x = \\tfrac{1}{2}.$$", subtopicSlugs: S },
    { content: "Let $g(x) = \\ln(x^2 + 1)$.\n\n**a.** Find $g'(x)$. (2 marks)\n\n**b.** Find the stationary point of $g$. (2 marks)\n\n**c.** Find $g''(x)$. (3 marks)\n\n**d.** Determine whether the stationary point is a maximum, minimum, or inflection. (2 marks)\n\n**e.** Find the tangent to $y = g(x)$ at $x = 1$. (3 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Chain rule with $u = x^2 + 1$.\n\n$$g'(x) = \\dfrac{1}{x^2 + 1} \\cdot 2x.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$g'(x) = \\dfrac{2x}{x^2 + 1}.$$\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Set $g'(x) = 0$: numerator $2x = 0$.\n\n*Step 2 (1 mark):* So $x = 0$, and $g(0) = \\ln 1 = 0$. Stationary point at $(0, 0)$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Use quotient rule on $\\dfrac{2x}{x^2 + 1}$.\n\n*Step 2 (1 mark):* Numerator: $2(x^2 + 1) - 2x \\cdot 2x = 2x^2 + 2 - 4x^2 = 2 - 2x^2$.\n\n*Step 3 (1 mark):* So\n\n$$g''(x) = \\dfrac{2 - 2x^2}{(x^2 + 1)^2}.$$\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* At $x = 0$, $g''(0) = \\dfrac{2}{1} = 2 > 0$.\n\n*Step 2 (1 mark):* So $(0, 0)$ is a local minimum.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* $g(1) = \\ln 2$.\n\n*Step 2 (1 mark):* $g'(1) = 2/2 = 1$.\n\n*Step 3 (1 mark):* Tangent: $y - \\ln 2 = 1 \\cdot (x - 1)$, so $y = x - 1 + \\ln 2$.", subtopicSlugs: S },
    { content: "A particle moves along a line with position $s(t) = \\sin(\\pi t / 2)$ metres at time $t \\geq 0$ seconds.\n\n**a.** Find the velocity $v(t) = s'(t)$. (2 marks)\n\n**b.** Find $v(0)$ and $v(1)$. (2 marks)\n\n**c.** Find the first time the particle is momentarily at rest. (3 marks)\n\n**d.** Find the acceleration $a(t) = v'(t)$. (2 marks)\n\n**e.** Show that $a(t) = -\\dfrac{\\pi^2}{4} s(t)$. (2 marks)\n\n**f.** Find $s(2)$ and interpret the result. (2 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Chain rule.\n\n$$v(t) = \\cos(\\pi t / 2) \\cdot \\dfrac{\\pi}{2}.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$v(t) = \\dfrac{\\pi}{2} \\cos(\\pi t / 2).$$\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $v(0) = \\dfrac{\\pi}{2} \\cos 0 = \\dfrac{\\pi}{2}$.\n\n*Step 2 (1 mark):* $v(1) = \\dfrac{\\pi}{2} \\cos(\\pi/2) = 0$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Set $v(t) = 0$.\n\n$$\\cos(\\pi t / 2) = 0.$$\n\n*Step 2 (1 mark):* Solve: $\\pi t / 2 = \\pi/2 + k\\pi$.\n\n*Step 3 (1 mark):* First positive solution: $t = 1$ s.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Differentiate $v$.\n\n$$a(t) = -\\dfrac{\\pi}{2} \\sin(\\pi t / 2) \\cdot \\dfrac{\\pi}{2}.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$a(t) = -\\dfrac{\\pi^2}{4} \\sin(\\pi t / 2).$$\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Recall $s(t) = \\sin(\\pi t / 2)$.\n\n*Step 2 (1 mark):* Substitute: $a(t) = -\\dfrac{\\pi^2}{4} \\sin(\\pi t / 2) = -\\dfrac{\\pi^2}{4} s(t)$. ✓\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $s(2) = \\sin(\\pi) = 0$.\n\n*Step 2 (1 mark):* The particle returns to its starting point at $t = 2$ s.", subtopicSlugs: S },
    { content: "Let $h(x) = (1 + 2x)^{10}$.\n\n**a.** Find $h'(x)$. (2 marks)\n\n**b.** Evaluate $h'(0)$. (1 mark)\n\n**c.** Find $h''(x)$. (3 marks)\n\n**d.** Find the equation of the tangent to $y = h(x)$ at the point where $x = 0$. (2 marks)\n\n**e.** Let $k(x) = (1 + 2x)^n$ for a positive integer $n$. Find $k'(0)$ in terms of $n$. (2 marks)", marks: 10, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Chain rule with $u = 1 + 2x$.\n\n$$h'(x) = 10(1 + 2x)^9 \\cdot 2.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$h'(x) = 20(1 + 2x)^9.$$\n\n**b. (1 mark)**\n\n*Step 1 (1 mark):* Evaluate.\n\n$$h'(0) = 20 \\cdot 1 = 20.$$\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Differentiate $h'(x) = 20(1 + 2x)^9$.\n\n*Step 2 (1 mark):* Apply chain rule.\n\n$$h''(x) = 20 \\cdot 9(1 + 2x)^8 \\cdot 2.$$\n\n*Step 3 (1 mark):* Simplify.\n\n$$h''(x) = 360(1 + 2x)^8.$$\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $h(0) = 1$, $h'(0) = 20$.\n\n*Step 2 (1 mark):* Tangent: $y = 20x + 1$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Chain rule.\n\n$$k'(x) = n(1 + 2x)^{n-1} \\cdot 2 = 2n(1 + 2x)^{n-1}.$$\n\n*Step 2 (1 mark):* At $x = 0$: $k'(0) = 2n$.", subtopicSlugs: S },
  ];
  writeQset(OUT("chain-rule"), { mcq, shortAnswer, extendedResponse });
}

