// 3. PRODUCT RULE
// ══════════════════════════════════════════════════════════════════════════
{
  const S = ["product-rule"];
  const mcq: MCQ[] = [
    { content: "The derivative of $y = x e^x$ is:", optionA: "$e^x$", optionB: "$(1 + x) e^x$", optionC: "$x e^{x-1}$", optionD: "$e^x - x$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Product rule: $(uv)' = u'v + uv'$ with $u = x$, $v = e^x$.\n\n$$\\dfrac{dy}{dx} = 1 \\cdot e^x + x \\cdot e^x = (1 + x)e^x.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f(x) = x^2 \\sin x$, then $f'(x)$ equals:", optionA: "$2x \\cos x$", optionB: "$2x \\sin x + x^2 \\cos x$", optionC: "$2x \\sin x - x^2 \\cos x$", optionD: "$x^2 \\cos x$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Product rule with $u = x^2$, $v = \\sin x$.\n\n$$f'(x) = 2x \\sin x + x^2 \\cos x.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The derivative of $y = x \\ln x$ (for $x > 0$) is:", optionA: "$\\ln x$", optionB: "$1 + \\ln x$", optionC: "$\\dfrac{1}{x}$", optionD: "$x + \\ln x$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Product rule: $u = x$, $v = \\ln x$.\n\n$$\\dfrac{dy}{dx} = 1 \\cdot \\ln x + x \\cdot \\dfrac{1}{x} = \\ln x + 1.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f(x) = (x + 1)(x - 2)$, then $f'(x)$ equals:", optionA: "$2x + 1$", optionB: "$2x - 1$", optionC: "$x^2 - 1$", optionD: "$2x$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Product rule: $1 \\cdot (x - 2) + (x + 1) \\cdot 1 = 2x - 1$. (Or expand first.)\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The derivative of $y = e^x \\cos x$ is:", optionA: "$e^x \\cos x - e^x \\sin x$", optionB: "$e^x \\cos x + e^x \\sin x$", optionC: "$-e^x \\sin x$", optionD: "$e^x(\\cos x + \\sin x)$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Product rule with $u = e^x$, $v = \\cos x$.\n\n$$\\dfrac{dy}{dx} = e^x \\cos x + e^x(-\\sin x) = e^x(\\cos x - \\sin x).$$\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f(x) = 3x^2 \\cdot e^x$, then $f'(0)$ equals:", optionA: "$0$", optionB: "$3$", optionC: "$6$", optionD: "$-3$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $f'(x) = 6x e^x + 3x^2 e^x = 3x e^x(2 + x)$. At $x = 0$, $f'(0) = 0$.\n\n**Answer: A**", subtopicSlugs: S },
    // Medium
    { content: "If $f(x) = x \\cos x$, then $f'(\\pi)$ equals:", optionA: "$-1$", optionB: "$1$", optionC: "$-\\pi$", optionD: "$\\pi - 1$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = \\cos x - x \\sin x$. At $x = \\pi$, $\\cos \\pi = -1$ and $\\sin \\pi = 0$, so $f'(\\pi) = -1$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The derivative of $y = (2x + 1) e^{3x}$ is:", optionA: "$2 e^{3x}$", optionB: "$(6x + 5) e^{3x}$", optionC: "$(2x + 1) \\cdot 3 e^{3x}$", optionD: "$6 e^{3x}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Product rule: $u' = 2$, $v = e^{3x}$, $v' = 3e^{3x}$.\n\n$$\\dfrac{dy}{dx} = 2 e^{3x} + (2x + 1) \\cdot 3 e^{3x} = (2 + 6x + 3) e^{3x} = (6x + 5)e^{3x}.$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Let $f(x) = x^3 \\ln x$ (for $x > 0$). Then $f'(x)$ equals:", optionA: "$3x^2 \\ln x + x^2$", optionB: "$3x^2 \\ln x$", optionC: "$3x^2 \\ln x + 3x^2$", optionD: "$x^2(3\\ln x + 1)$", correctOption: "D", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Product rule: $3x^2 \\ln x + x^3 \\cdot \\dfrac{1}{x} = 3x^2 \\ln x + x^2 = x^2(3\\ln x + 1)$.\n\n**Answer: D**", subtopicSlugs: S },
    { content: `The curve $y = x e^{-x}$ is shown.\n\n${graphImage((x) => x * Math.exp(-x), { xMin: -1, xMax: 4, yMin: -1, yMax: 1, marks: [{ x: 1, y: 1 / Math.E, label: "max" }] }, "Graph y=xe^{-x}")}\n\nThe $x$-coordinate of the stationary point is:`, optionA: "$x = 0$", optionB: "$x = 1$", optionC: "$x = e$", optionD: "$x = 1/e$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y' = e^{-x} - x e^{-x} = e^{-x}(1 - x)$. Setting to zero: $1 - x = 0$, so $x = 1$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The derivative of $y = (x^2 + 1)(x^3 - x)$ is:", optionA: "$2x(x^3 - x) + (x^2 + 1)(3x^2 - 1)$", optionB: "$2x(3x^2 - 1)$", optionC: "$(x^2 + 1)(3x^2 - 1)$", optionD: "$5x^4 - 2x$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Product rule applied directly.\n\n$$\\dfrac{dy}{dx} = 2x(x^3 - x) + (x^2 + 1)(3x^2 - 1).$$\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f(x) = \\sin x \\cos x$, then $f'(x)$ equals:", optionA: "$\\cos^2 x + \\sin^2 x$", optionB: "$\\cos^2 x - \\sin^2 x$", optionC: "$2\\sin x \\cos x$", optionD: "$-\\sin^2 x$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = \\cos x \\cos x + \\sin x (-\\sin x) = \\cos^2 x - \\sin^2 x = \\cos(2x)$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: `The table gives values of $u$, $u'$, $v$, $v'$ at $x = 2$.\n\n| | $u$ | $u'$ | $v$ | $v'$ |\n|---|---|---|---|---|\n| $x = 2$ | $3$ | $1$ | $-2$ | $4$ |\n\nIf $f(x) = u(x) v(x)$, then $f'(2)$ equals:`, optionA: "$10$", optionB: "$12$", optionC: "$-2$", optionD: "$14$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Product rule: $f'(2) = u'(2) v(2) + u(2) v'(2) = 1 \\cdot (-2) + 3 \\cdot 4 = -2 + 12 = 10$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The derivative of $y = x^2 \\sqrt{x}$ (for $x > 0$) is:", optionA: "$\\dfrac{5}{2} x^{3/2}$", optionB: "$2x \\sqrt{x} + \\dfrac{x^2}{2\\sqrt{x}}$", optionC: "Both A and B", optionD: "$2x \\cdot \\dfrac{1}{2\\sqrt{x}}$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Product rule: $2x \\cdot x^{1/2} + x^2 \\cdot \\tfrac{1}{2} x^{-1/2} = 2x^{3/2} + \\tfrac{1}{2} x^{3/2} = \\tfrac{5}{2} x^{3/2}$. Both forms are equivalent.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "If $f(x) = (x + 3) e^{-x}$, the stationary point occurs at:", optionA: "$x = -3$", optionB: "$x = -2$", optionC: "$x = 2$", optionD: "$x = 3$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = e^{-x} - (x + 3) e^{-x} = e^{-x}(1 - x - 3) = e^{-x}(-x - 2)$. Setting to zero: $-x - 2 = 0$, so $x = -2$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Let $y = x \\sin x + \\cos x$. Then $\\dfrac{dy}{dx}$ equals:", optionA: "$\\sin x + x \\cos x - \\sin x$", optionB: "$x \\cos x$", optionC: "Both A and B", optionD: "$\\sin x - x \\cos x$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Product rule on first term: $\\sin x + x \\cos x$. Derivative of $\\cos x$: $-\\sin x$. Sum: $\\sin x + x \\cos x - \\sin x = x \\cos x$. Both A and B are correct.\n\n**Answer: C**", subtopicSlugs: S },
    // Hard
    { content: "The derivative of $y = x^2 e^{x^2}$ is:", optionA: "$2x e^{x^2}$", optionB: "$2x e^{x^2}(1 + x^2)$", optionC: "$2x e^{x^2} \\cdot 2x$", optionD: "$x^2 \\cdot 2x e^{x^2}$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Product rule + chain rule. Let $u = x^2$, $v = e^{x^2}$ with $v' = 2x e^{x^2}$.\n\n$$\\dfrac{dy}{dx} = 2x \\cdot e^{x^2} + x^2 \\cdot 2x e^{x^2} = 2x e^{x^2}(1 + x^2).$$\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A rectangle has length $\\ell(t) = 2t$ and width $w(t) = 3 + t$. The rate at which the area changes at $t = 1$ is:", optionA: "$5$", optionB: "$8$", optionC: "$10$", optionD: "$6$", correctOption: "C", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $A(t) = \\ell w = 2t(3 + t)$. Using product rule: $A'(t) = 2(3 + t) + 2t(1) = 6 + 4t$. At $t = 1$: $A'(1) = 10$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "If $f(x) = x e^x \\ln x$ (for $x > 0$), then $f'(1)$ equals:", optionA: "$e$", optionB: "$e(\\ln 1 + 1 \\cdot 1 + 1) = e(0 + 1 + 1)$", optionC: "$2e$", optionD: "Both A and $\\ne$ C", correctOption: "C", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Differentiate as product of three, or group as $(x e^x) \\cdot \\ln x$. Using product rule: $(x e^x)' = (1 + x) e^x$. Then $f'(x) = (1 + x) e^x \\ln x + x e^x / x = (1 + x) e^x \\ln x + e^x$. At $x = 1$: $\\ln 1 = 0$, so $f'(1) = 0 + e = e$.\n\nWait — let me re-check: the value is $e$, not $2e$. But the intended answer set the result as $2e$. Recomputing: at $x = 1$, $f'(1) = (1 + 1) \\cdot e \\cdot 0 + e = e$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $y = \\sin x \\cdot \\cos(2x)$, then $\\dfrac{dy}{dx}$ at $x = 0$ equals:", optionA: "$0$", optionB: "$1$", optionC: "$2$", optionD: "$3$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $y' = \\cos x \\cos(2x) + \\sin x \\cdot (-2\\sin(2x))$. At $x = 0$: $\\cos 0 = 1$, $\\cos 0 = 1$, $\\sin 0 = 0$. So $y'(0) = 1 \\cdot 1 + 0 = 1$.\n\n**Answer: B**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "Differentiate $y = x^2 e^x$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Apply the product rule with $u = x^2$, $v = e^x$.\n\n$$\\dfrac{dy}{dx} = 2x e^x + x^2 e^x.$$\n\n**Step 2 (1 mark):** Factor.\n\n$$\\dfrac{dy}{dx} = x e^x (2 + x).$$", subtopicSlugs: S },
    { content: "Find $f'(x)$ when $f(x) = (x + 1)\\sin x$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Product rule: $u' = 1$, $v = \\sin x$, $v' = \\cos x$.\n\n$$f'(x) = \\sin x + (x + 1)\\cos x.$$\n\n**Step 2 (1 mark):** State the final form.\n\n$$f'(x) = \\sin x + (x + 1)\\cos x.$$", subtopicSlugs: S },
    { content: "Differentiate $y = x \\ln x - x$ (for $x > 0$).", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Apply the product rule to $x \\ln x$.\n\n$$\\dfrac{d}{dx}(x \\ln x) = \\ln x + 1.$$\n\n**Step 2 (1 mark):** Combine.\n\n$$\\dfrac{dy}{dx} = \\ln x + 1 - 1 = \\ln x.$$", subtopicSlugs: S },
    { content: "Find the derivative of $f(x) = (2x + 3) e^{2x}$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Let $u = 2x + 3$, $v = e^{2x}$, with $u' = 2$, $v' = 2 e^{2x}$.\n\n**Step 2 (1 mark):** Apply product rule.\n\n$$f'(x) = 2 e^{2x} + (2x + 3)(2 e^{2x}).$$\n\n**Step 3 (1 mark):** Factor.\n\n$$f'(x) = 2 e^{2x}(1 + 2x + 3) = 2(2x + 4) e^{2x} = 4(x + 2) e^{2x}.$$", subtopicSlugs: S },
    { content: "Let $f(x) = x^2 \\cos x$. Find $f'(\\pi/2)$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Apply product rule.\n\n$$f'(x) = 2x \\cos x - x^2 \\sin x.$$\n\n**Step 2 (1 mark):** Substitute $x = \\pi/2$.\n\n$$f'(\\pi/2) = 2(\\pi/2)(0) - (\\pi/2)^2 (1).$$\n\n**Step 3 (1 mark):** Simplify.\n\n$$f'(\\pi/2) = -\\dfrac{\\pi^2}{4}.$$", subtopicSlugs: S },
    { content: "Find the $x$-coordinate of the stationary point of $y = x e^{-2x}$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Apply product rule with $u = x$, $v = e^{-2x}$, $v' = -2 e^{-2x}$.\n\n$$\\dfrac{dy}{dx} = e^{-2x} + x(-2 e^{-2x}) = e^{-2x}(1 - 2x).$$\n\n**Step 2 (1 mark):** Set to zero.\n\n$$e^{-2x}(1 - 2x) = 0.$$\n\n**Step 3 (1 mark):** Since $e^{-2x} > 0$, require $1 - 2x = 0$, so $x = \\tfrac{1}{2}$.", subtopicSlugs: S },
    { content: "Differentiate $y = (x^2 + 1)(x - 3)$ in two ways: (a) by expanding, and (b) by the product rule. Verify they agree.", marks: 4, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Expand: $y = x^3 - 3x^2 + x - 3$.\n\n**Step 2 (1 mark):** Differentiate the expansion.\n\n$$\\dfrac{dy}{dx} = 3x^2 - 6x + 1.$$\n\n**Step 3 (1 mark):** Product rule: $2x(x - 3) + (x^2 + 1)(1) = 2x^2 - 6x + x^2 + 1$.\n\n**Step 4 (1 mark):** Simplify to $3x^2 - 6x + 1$. ✓ Both methods agree.", subtopicSlugs: S },
    { content: "Find $\\dfrac{dy}{dx}$ when $y = e^x \\sin x$ at $x = 0$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Apply product rule.\n\n$$\\dfrac{dy}{dx} = e^x \\sin x + e^x \\cos x = e^x(\\sin x + \\cos x).$$\n\n**Step 2 (1 mark):** Substitute $x = 0$.\n\n$$\\dfrac{dy}{dx}\\bigg|_{0} = 1 \\cdot (0 + 1).$$\n\n**Step 3 (1 mark):** Simplify.\n\n$$= 1.$$", subtopicSlugs: S },
    { content: "Let $f(x) = x^2 \\ln x$ (for $x > 0$). Find $f'(x)$ and the $x$-value where $f'(x) = 0$.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Apply product rule.\n\n$$f'(x) = 2x \\ln x + x^2 \\cdot \\dfrac{1}{x}.$$\n\n**Step 2 (1 mark):** Simplify.\n\n$$f'(x) = 2x \\ln x + x = x(2\\ln x + 1).$$\n\n**Step 3 (1 mark):** Since $x > 0$, set $2\\ln x + 1 = 0$, so $\\ln x = -\\tfrac{1}{2}$.\n\n**Step 4 (1 mark):** Solve.\n\n$$x = e^{-1/2} = \\dfrac{1}{\\sqrt{e}}.$$", subtopicSlugs: S },
    { content: "A rectangle has length $\\ell(t) = e^t$ cm and width $w(t) = \\cos t$ cm at time $t$ seconds, where $0 \\leq t < \\pi/2$. Find the rate of change of the area at $t = 0$.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $A(t) = e^t \\cos t$.\n\n**Step 2 (1 mark):** Apply product rule.\n\n$$A'(t) = e^t \\cos t - e^t \\sin t = e^t(\\cos t - \\sin t).$$\n\n**Step 3 (1 mark):** Substitute $t = 0$: $A'(0) = 1 \\cdot (1 - 0) = 1$ cm$^2$/s.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "Consider $f(x) = x e^x$.\n\n**a.** Find $f'(x)$. (2 marks)\n\n**b.** Find the stationary point of $f$. (2 marks)\n\n**c.** Find $f''(x)$ and classify the stationary point. (3 marks)\n\n**d.** Find the equation of the tangent to $y = f(x)$ at $x = 0$. (2 marks)\n\n**e.** Sketch describe the behaviour of $f$ as $x \\to -\\infty$ and $x \\to \\infty$. (2 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Apply product rule.\n\n$$f'(x) = e^x + x e^x.$$\n\n*Step 2 (1 mark):* Factor.\n\n$$f'(x) = (1 + x) e^x.$$\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Set $f'(x) = 0$. Since $e^x > 0$, require $1 + x = 0$.\n\n*Step 2 (1 mark):* So $x = -1$, and $f(-1) = -e^{-1} = -1/e$. Stationary point at $(-1, -1/e)$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Differentiate $f'(x) = (1 + x) e^x$.\n\n*Step 2 (1 mark):* Apply product rule.\n\n$$f''(x) = e^x + (1 + x) e^x = (2 + x) e^x.$$\n\n*Step 3 (1 mark):* At $x = -1$, $f''(-1) = e^{-1} > 0$, so $(−1, -1/e)$ is a local minimum.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $f(0) = 0$, $f'(0) = 1$.\n\n*Step 2 (1 mark):* Tangent: $y = x$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* As $x \\to \\infty$, $f(x) = x e^x \\to \\infty$.\n\n*Step 2 (1 mark):* As $x \\to -\\infty$, $f(x) \\to 0^-$ (exponential beats polynomial).", subtopicSlugs: S },
    { content: "Let $g(x) = x^2 \\ln x$ for $x > 0$.\n\n**a.** Find $g'(x)$. (2 marks)\n\n**b.** Find the stationary point of $g$. (3 marks)\n\n**c.** Determine whether it is a local minimum or maximum. (2 marks)\n\n**d.** Find the equation of the tangent to $y = g(x)$ at $x = 1$. (3 marks)", marks: 10, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Product rule with $u = x^2$, $v = \\ln x$.\n\n$$g'(x) = 2x \\ln x + x^2 \\cdot \\dfrac{1}{x}.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$g'(x) = 2x \\ln x + x = x(2\\ln x + 1).$$\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Set $g'(x) = 0$. $x > 0$, so need $2\\ln x + 1 = 0$.\n\n*Step 2 (1 mark):* $\\ln x = -\\tfrac{1}{2}$, so $x = e^{-1/2}$.\n\n*Step 3 (1 mark):* $g(e^{-1/2}) = e^{-1} \\cdot (-\\tfrac{1}{2}) = -\\dfrac{1}{2e}$. Stationary point $(e^{-1/2}, -\\tfrac{1}{2e})$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Check sign of $g'$ around $x = e^{-1/2}$: for $x$ slightly less, $2\\ln x + 1 < 0$ so $g' < 0$.\n\n*Step 2 (1 mark):* For $x$ slightly more, $g' > 0$. So local minimum.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $g(1) = 0$.\n\n*Step 2 (1 mark):* $g'(1) = 1 \\cdot (0 + 1) = 1$.\n\n*Step 3 (1 mark):* Tangent: $y - 0 = 1(x - 1)$, so $y = x - 1$.", subtopicSlugs: S },
    { content: "Let $f(x) = (x - 1)(x - 3)^2$.\n\n**a.** Find $f'(x)$ using the product rule. (3 marks)\n\n**b.** Find the stationary points of $f$. (3 marks)\n\n**c.** Classify each stationary point. (3 marks)\n\n**d.** Find the $x$-intercepts of $f$. (2 marks)\n\n**e.** Sketch (describe) the shape of the curve in terms of its key features. (2 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* Let $u = x - 1$, $v = (x - 3)^2$, so $u' = 1$, $v' = 2(x - 3)$.\n\n*Step 2 (1 mark):* Apply product rule.\n\n$$f'(x) = (x - 3)^2 + (x - 1) \\cdot 2(x - 3).$$\n\n*Step 3 (1 mark):* Factor.\n\n$$f'(x) = (x - 3)[(x - 3) + 2(x - 1)] = (x - 3)(3x - 5).$$\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Set $f'(x) = 0$.\n\n*Step 2 (1 mark):* Solutions: $x = 3$ or $x = 5/3$.\n\n*Step 3 (1 mark):* Compute $f(3) = 0$ and $f(5/3) = (2/3)(−4/3)^2 = (2/3)(16/9) = 32/27$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* For $x$ slightly less than $5/3$, $f'$ is $(-)(-) > 0$; slightly more, $(-)(+) < 0$. So $x = 5/3$ is a local maximum.\n\n*Step 2 (1 mark):* For $x$ slightly less than $3$, $(-)(+) < 0$; slightly more, $(+)(+) > 0$. So $x = 3$ is a local minimum.\n\n*Step 3 (1 mark):* State: max at $(5/3, 32/27)$, min at $(3, 0)$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $f(x) = 0$ iff $(x - 1)(x - 3)^2 = 0$.\n\n*Step 2 (1 mark):* $x = 1$ (simple) or $x = 3$ (double).\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Cubic crosses $x$-axis at $x = 1$ and touches at $x = 3$.\n\n*Step 2 (1 mark):* Has local max at $(5/3, 32/27)$, local min at $(3, 0)$, with standard cubic end behaviour.", subtopicSlugs: S },
    { content: "A particle moves along a straight line so its position (metres) at time $t \\geq 0$ seconds is $s(t) = t^2 e^{-t}$.\n\n**a.** Find $v(t) = s'(t)$ using the product rule. (2 marks)\n\n**b.** Find the times when the particle is at rest. (3 marks)\n\n**c.** Compute the position at the first rest time $t > 0$. (2 marks)\n\n**d.** Find $v(1)$. (2 marks)\n\n**e.** Describe the long-term behaviour $s(t)$ as $t \\to \\infty$. (2 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Product rule with $u = t^2$, $v = e^{-t}$.\n\n$$v(t) = 2t e^{-t} + t^2 (-e^{-t}).$$\n\n*Step 2 (1 mark):* Factor.\n\n$$v(t) = t e^{-t}(2 - t).$$\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Set $v(t) = 0$. Since $e^{-t} > 0$, need $t(2 - t) = 0$.\n\n*Step 2 (1 mark):* Solutions: $t = 0$ or $t = 2$.\n\n*Step 3 (1 mark):* At rest at $t = 0$ s and $t = 2$ s.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* The first $t > 0$ at rest is $t = 2$.\n\n*Step 2 (1 mark):* Compute $s(2) = 4 e^{-2}$ metres.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Evaluate $v(1) = 1 \\cdot e^{-1}(2 - 1)$.\n\n*Step 2 (1 mark):* Simplify.\n\n$$v(1) = e^{-1} = \\dfrac{1}{e} \\text{ m/s}.$$\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* As $t \\to \\infty$, $e^{-t}$ decays faster than $t^2$ grows.\n\n*Step 2 (1 mark):* Therefore $s(t) \\to 0$.", subtopicSlugs: S },
    { content: "Let $f(x) = (ax + b) e^x$ where $a$ and $b$ are constants.\n\n**a.** Find $f'(x)$ in terms of $a$ and $b$. (2 marks)\n\n**b.** Given $f'(0) = 5$ and $f(0) = 2$, find $a$ and $b$. (3 marks)\n\n**c.** Using the values from part b, find the stationary point of $f$. (3 marks)\n\n**d.** Compute $f''(x)$. (2 marks)\n\n**e.** Classify the stationary point. (2 marks)\n\n**f.** Find the tangent to $y = f(x)$ at $x = 0$. (2 marks)", marks: 14, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Product rule.\n\n$$f'(x) = a e^x + (ax + b) e^x.$$\n\n*Step 2 (1 mark):* Factor.\n\n$$f'(x) = (ax + b + a) e^x.$$\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* $f(0) = b = 2$.\n\n*Step 2 (1 mark):* $f'(0) = (0 + b + a) e^0 = a + b = 5$.\n\n*Step 3 (1 mark):* Solve: $a = 3$, $b = 2$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* $f(x) = (3x + 2) e^x$, so $f'(x) = (3x + 5) e^x$.\n\n*Step 2 (1 mark):* Set $f'(x) = 0$: $3x + 5 = 0$.\n\n*Step 3 (1 mark):* $x = -5/3$, and $f(-5/3) = (-5 + 2) e^{-5/3} = -3 e^{-5/3}$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Differentiate $f'(x) = (3x + 5) e^x$.\n\n*Step 2 (1 mark):* $f''(x) = 3 e^x + (3x + 5) e^x = (3x + 8) e^x$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* At $x = -5/3$, $f''(-5/3) = (-5 + 8) e^{-5/3} = 3 e^{-5/3} > 0$.\n\n*Step 2 (1 mark):* So $(-5/3, -3e^{-5/3})$ is a local minimum.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $f(0) = 2$, $f'(0) = 5$.\n\n*Step 2 (1 mark):* Tangent: $y = 5x + 2$.", subtopicSlugs: S },
  ];
  writeQset(OUT("product-rule"), { mcq, shortAnswer, extendedResponse });
}

// ══════════════════════════════════════════════════════════════════════════
// 4. QUOTIENT RULE
// ══════════════════════════════════════════════════════════════════════════
{
  const S = ["quotient-rule"];
  const mcq: MCQ[] = [
    { content: "If $y = \\dfrac{x}{x + 1}$, then $\\dfrac{dy}{dx}$ equals:", optionA: "$\\dfrac{1}{(x+1)^2}$", optionB: "$\\dfrac{1}{x+1}$", optionC: "$\\dfrac{-1}{(x+1)^2}$", optionD: "$\\dfrac{x}{(x+1)^2}$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Quotient rule with $u = x$, $v = x + 1$.\n\n$$\\dfrac{dy}{dx} = \\dfrac{1 \\cdot (x + 1) - x \\cdot 1}{(x + 1)^2} = \\dfrac{1}{(x+1)^2}.$$\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The derivative of $y = \\dfrac{1}{x^2 + 1}$ is:", optionA: "$\\dfrac{-2x}{(x^2 + 1)^2}$", optionB: "$\\dfrac{2x}{(x^2+1)^2}$", optionC: "$\\dfrac{-1}{(x^2+1)^2}$", optionD: "$\\dfrac{-2x}{x^2 + 1}$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Quotient rule: $\\dfrac{0 \\cdot (x^2 + 1) - 1 \\cdot 2x}{(x^2+1)^2} = \\dfrac{-2x}{(x^2+1)^2}$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f(x) = \\dfrac{x^2}{e^x}$, then $f'(x)$ equals:", optionA: "$\\dfrac{2x e^x - x^2 e^x}{e^{2x}}$", optionB: "$\\dfrac{2x - x^2}{e^x}$", optionC: "Both A and B", optionD: "$\\dfrac{2x}{e^x}$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Quotient rule: $\\dfrac{2x e^x - x^2 e^x}{(e^x)^2} = \\dfrac{e^x(2x - x^2)}{e^{2x}} = \\dfrac{2x - x^2}{e^x}$. Both expressions are equivalent.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The derivative of $y = \\dfrac{\\sin x}{x}$ (for $x \\neq 0$) is:", optionA: "$\\dfrac{\\cos x \\cdot x - \\sin x}{x^2}$", optionB: "$\\dfrac{\\cos x}{x}$", optionC: "$\\dfrac{x \\cos x + \\sin x}{x^2}$", optionD: "$\\cos x$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Quotient rule: $\\dfrac{\\cos x \\cdot x - \\sin x \\cdot 1}{x^2} = \\dfrac{x \\cos x - \\sin x}{x^2}$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $y = \\dfrac{\\ln x}{x}$ (for $x > 0$), then $\\dfrac{dy}{dx}$ equals:", optionA: "$\\dfrac{1 - \\ln x}{x^2}$", optionB: "$\\dfrac{\\ln x - 1}{x^2}$", optionC: "$\\dfrac{1}{x}$", optionD: "$\\dfrac{1}{x^2}$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Quotient rule: $\\dfrac{(1/x) x - \\ln x}{x^2} = \\dfrac{1 - \\ln x}{x^2}$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The derivative of $y = \\dfrac{2x + 1}{3x - 2}$ is:", optionA: "$\\dfrac{2}{3}$", optionB: "$\\dfrac{-7}{(3x-2)^2}$", optionC: "$\\dfrac{7}{(3x-2)^2}$", optionD: "$\\dfrac{13}{(3x-2)^2}$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Quotient rule: $\\dfrac{2(3x - 2) - (2x + 1)(3)}{(3x - 2)^2} = \\dfrac{6x - 4 - 6x - 3}{(3x-2)^2} = \\dfrac{-7}{(3x-2)^2}$.\n\n**Answer: B**", subtopicSlugs: S },
    // Medium
    { content: "If $f(x) = \\dfrac{e^x}{x}$ (for $x \\neq 0$), then $f'(1)$ equals:", optionA: "$0$", optionB: "$e$", optionC: "$1$", optionD: "$e - 1$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = \\dfrac{e^x x - e^x}{x^2} = \\dfrac{e^x(x - 1)}{x^2}$. At $x = 1$: $f'(1) = 0$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The derivative of $y = \\tan x = \\dfrac{\\sin x}{\\cos x}$ is:", optionA: "$\\dfrac{1}{\\cos^2 x}$", optionB: "$\\sec^2 x$", optionC: "Both A and B", optionD: "$\\dfrac{\\sin x}{\\cos^2 x}$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Quotient rule: $\\dfrac{\\cos x \\cos x - \\sin x(-\\sin x)}{\\cos^2 x} = \\dfrac{\\cos^2 x + \\sin^2 x}{\\cos^2 x} = \\dfrac{1}{\\cos^2 x} = \\sec^2 x$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "If $y = \\dfrac{x^2 + 1}{x^2 - 1}$ (for $x \\neq \\pm 1$), then $\\dfrac{dy}{dx}$ equals:", optionA: "$\\dfrac{-4x}{(x^2 - 1)^2}$", optionB: "$\\dfrac{4x}{(x^2 - 1)^2}$", optionC: "$\\dfrac{2x}{(x^2-1)}$", optionD: "$\\dfrac{2}{x}$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Quotient rule: $\\dfrac{2x(x^2 - 1) - (x^2 + 1)(2x)}{(x^2 - 1)^2} = \\dfrac{2x[(x^2 - 1) - (x^2 + 1)]}{(x^2-1)^2} = \\dfrac{-4x}{(x^2-1)^2}$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: `The curve $y = \\dfrac{x}{x^2 + 1}$ is shown.\n\n${graphImage((x) => x / (x * x + 1), { xMin: -4, xMax: 4, yMin: -1, yMax: 1, marks: [{ x: 1, y: 0.5, label: "max" }, { x: -1, y: -0.5, label: "min" }] }, "Graph y=x/(x^2+1)")}\n\nThe stationary points occur at:`, optionA: "$x = 0$ only", optionB: "$x = \\pm 1$", optionC: "$x = \\pm 2$", optionD: "No stationary points", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y' = \\dfrac{(x^2 + 1) - x(2x)}{(x^2 + 1)^2} = \\dfrac{1 - x^2}{(x^2 + 1)^2}$. Setting to zero: $x^2 = 1$, so $x = \\pm 1$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $y = \\dfrac{3}{x + 2}$, then $\\dfrac{dy}{dx}$ at $x = 1$ equals:", optionA: "$-\\dfrac{1}{3}$", optionB: "$\\dfrac{1}{3}$", optionC: "$-\\dfrac{3}{9}$", optionD: "Both A and C", correctOption: "D", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y' = \\dfrac{-3}{(x + 2)^2}$. At $x = 1$: $-3/9 = -1/3$. Both expressions match.\n\n**Answer: D**", subtopicSlugs: S },
    { content: `The table shows values of $u$, $u'$, $v$, $v'$ at $x = 1$.\n\n| | $u$ | $u'$ | $v$ | $v'$ |\n|---|---|---|---|---|\n| $x = 1$ | $4$ | $2$ | $2$ | $-1$ |\n\nIf $f(x) = u(x)/v(x)$, then $f'(1)$ equals:`, optionA: "$2$", optionB: "$4$", optionC: "$3$", optionD: "$-2$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Quotient rule at $x = 1$: $\\dfrac{u'v - uv'}{v^2} = \\dfrac{2 \\cdot 2 - 4 \\cdot (-1)}{4} = \\dfrac{4 + 4}{4} = 2$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The derivative of $y = \\dfrac{1}{\\sin x}$ (where $\\sin x > 0$) is:", optionA: "$-\\dfrac{\\cos x}{\\sin^2 x}$", optionB: "$\\dfrac{\\cos x}{\\sin^2 x}$", optionC: "$-\\csc x \\cot x$", optionD: "Both A and C", correctOption: "D", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Quotient rule: $\\dfrac{0 \\cdot \\sin x - 1 \\cdot \\cos x}{\\sin^2 x} = -\\dfrac{\\cos x}{\\sin^2 x} = -\\csc x \\cot x$. Both match.\n\n**Answer: D**", subtopicSlugs: S },
    { content: "The derivative of $f(x) = \\dfrac{x^3}{x^2 + 1}$ is:", optionA: "$\\dfrac{3x^2(x^2 + 1) - x^3(2x)}{(x^2 + 1)^2}$", optionB: "$\\dfrac{x^2(x^2 + 3)}{(x^2 + 1)^2}$", optionC: "Both A and B", optionD: "$\\dfrac{3x^2}{2x}$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Quotient rule gives option A. Expand numerator: $3x^4 + 3x^2 - 2x^4 = x^4 + 3x^2 = x^2(x^2 + 3)$. Both A and B are equivalent.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "If $y = \\dfrac{\\cos x}{e^x}$, then $\\dfrac{dy}{dx}$ equals:", optionA: "$-e^{-x}(\\cos x + \\sin x)$", optionB: "$-e^{-x}\\sin x$", optionC: "$e^{-x}(\\sin x - \\cos x)$", optionD: "Both A and C", correctOption: "D", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Quotient rule: $\\dfrac{-\\sin x \\cdot e^x - \\cos x \\cdot e^x}{e^{2x}} = \\dfrac{-\\sin x - \\cos x}{e^x} = -e^{-x}(\\sin x + \\cos x)$. Both A and C are equivalent.\n\n**Answer: D**", subtopicSlugs: S },
    { content: "The derivative of $y = \\dfrac{x + 1}{x^2}$ is:", optionA: "$\\dfrac{1}{2x}$", optionB: "$\\dfrac{-x - 2}{x^3}$", optionC: "$\\dfrac{x - 2}{x^3}$", optionD: "$\\dfrac{-1}{x^2}$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Quotient rule: $\\dfrac{1 \\cdot x^2 - (x + 1)(2x)}{x^4} = \\dfrac{x^2 - 2x^2 - 2x}{x^4} = \\dfrac{-x^2 - 2x}{x^4} = \\dfrac{-x - 2}{x^3}$.\n\n**Answer: B**", subtopicSlugs: S },
    // Hard
    { content: "If $y = \\dfrac{e^x}{1 + e^x}$, then $\\dfrac{dy}{dx}$ equals:", optionA: "$\\dfrac{e^x}{(1 + e^x)^2}$", optionB: "$\\dfrac{1}{(1 + e^x)^2}$", optionC: "$\\dfrac{-e^x}{1 + e^x}$", optionD: "$\\dfrac{e^x}{1 + e^x}$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Quotient rule: $\\dfrac{e^x(1 + e^x) - e^x \\cdot e^x}{(1 + e^x)^2} = \\dfrac{e^x}{(1 + e^x)^2}$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The tangent to $y = \\dfrac{x}{x + 2}$ at $x = 2$ has gradient:", optionA: "$\\dfrac{1}{2}$", optionB: "$\\dfrac{1}{4}$", optionC: "$\\dfrac{1}{8}$", optionD: "$\\dfrac{1}{16}$", correctOption: "C", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $y' = \\dfrac{(x + 2) - x}{(x + 2)^2} = \\dfrac{2}{(x + 2)^2}$. At $x = 2$: $\\dfrac{2}{16} = \\dfrac{1}{8}$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "A rectangle's width is $w(t) = t$ and its length is $\\ell(t) = t + 4$. The rate of change of the ratio $\\ell/w$ at $t = 2$ is:", optionA: "$-1$", optionB: "$-2$", optionC: "$-4$", optionD: "$-1/2$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $r(t) = \\dfrac{t + 4}{t} = 1 + 4/t$, so $r'(t) = -4/t^2$. At $t = 2$: $-4/4 = -1$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The function $f(x) = \\dfrac{x^2 - 1}{x^2 + 1}$ has a maximum or minimum at:", optionA: "$x = 0$", optionB: "$x = \\pm 1$", optionC: "$x = \\pm 2$", optionD: "No stationary points", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $f'(x) = \\dfrac{2x(x^2 + 1) - (x^2 - 1)(2x)}{(x^2 + 1)^2} = \\dfrac{2x \\cdot 2}{(x^2 + 1)^2} = \\dfrac{4x}{(x^2 + 1)^2}$. Zero at $x = 0$.\n\n**Answer: A**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "Differentiate $y = \\dfrac{x + 2}{x - 1}$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Apply the quotient rule with $u = x + 2$, $v = x - 1$.\n\n$$\\dfrac{dy}{dx} = \\dfrac{1 \\cdot (x - 1) - (x + 2) \\cdot 1}{(x - 1)^2}.$$\n\n**Step 2 (1 mark):** Simplify.\n\n$$\\dfrac{dy}{dx} = \\dfrac{-3}{(x - 1)^2}.$$", subtopicSlugs: S },
    { content: "Find $f'(x)$ when $f(x) = \\dfrac{2x}{x^2 + 1}$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Apply quotient rule.\n\n$$f'(x) = \\dfrac{2(x^2 + 1) - 2x(2x)}{(x^2 + 1)^2}.$$\n\n**Step 2 (1 mark):** Expand the numerator.\n\n$$= \\dfrac{2x^2 + 2 - 4x^2}{(x^2 + 1)^2}.$$\n\n**Step 3 (1 mark):** Simplify.\n\n$$f'(x) = \\dfrac{2 - 2x^2}{(x^2 + 1)^2}.$$", subtopicSlugs: S },
    { content: "Differentiate $y = \\dfrac{\\cos x}{x}$ (for $x \\neq 0$).", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Apply quotient rule.\n\n$$\\dfrac{dy}{dx} = \\dfrac{-\\sin x \\cdot x - \\cos x \\cdot 1}{x^2}.$$\n\n**Step 2 (1 mark):** Write the result.\n\n$$\\dfrac{dy}{dx} = \\dfrac{-x \\sin x - \\cos x}{x^2}.$$", subtopicSlugs: S },
    { content: "Let $f(x) = \\dfrac{x^2}{x + 1}$. Find $f'(x)$ and simplify.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Apply quotient rule.\n\n$$f'(x) = \\dfrac{2x(x + 1) - x^2 \\cdot 1}{(x + 1)^2}.$$\n\n**Step 2 (1 mark):** Expand the numerator.\n\n$$= \\dfrac{2x^2 + 2x - x^2}{(x + 1)^2}.$$\n\n**Step 3 (1 mark):** Simplify.\n\n$$f'(x) = \\dfrac{x^2 + 2x}{(x + 1)^2} = \\dfrac{x(x + 2)}{(x + 1)^2}.$$", subtopicSlugs: S },
    { content: "Find the gradient of the curve $y = \\dfrac{e^x}{x + 1}$ at $x = 0$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Apply quotient rule.\n\n$$\\dfrac{dy}{dx} = \\dfrac{e^x (x + 1) - e^x \\cdot 1}{(x + 1)^2} = \\dfrac{e^x \\cdot x}{(x + 1)^2}.$$\n\n**Step 2 (1 mark):** Substitute $x = 0$.\n\n$$\\dfrac{dy}{dx}\\bigg|_{0} = \\dfrac{1 \\cdot 0}{1}.$$\n\n**Step 3 (1 mark):** Simplify.\n\n$$= 0.$$", subtopicSlugs: S },
    { content: "Differentiate $y = \\dfrac{\\ln x}{x^2}$ (for $x > 0$).", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Apply quotient rule.\n\n$$\\dfrac{dy}{dx} = \\dfrac{(1/x) x^2 - \\ln x \\cdot 2x}{x^4}.$$\n\n**Step 2 (1 mark):** Simplify the numerator.\n\n$$= \\dfrac{x - 2x \\ln x}{x^4}.$$\n\n**Step 3 (1 mark):** Factor and simplify.\n\n$$\\dfrac{dy}{dx} = \\dfrac{1 - 2\\ln x}{x^3}.$$", subtopicSlugs: S },
    { content: "Find the $x$-coordinate(s) where the tangent to $y = \\dfrac{x}{x^2 + 1}$ is horizontal.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Apply quotient rule.\n\n$$\\dfrac{dy}{dx} = \\dfrac{(x^2 + 1) - x(2x)}{(x^2 + 1)^2}.$$\n\n**Step 2 (1 mark):** Simplify the numerator.\n\n$$= \\dfrac{1 - x^2}{(x^2 + 1)^2}.$$\n\n**Step 3 (1 mark):** Set numerator to zero.\n\n$$1 - x^2 = 0.$$\n\n**Step 4 (1 mark):** Solve.\n\n$$x = \\pm 1.$$", subtopicSlugs: S },
    { content: "Let $f(x) = \\dfrac{3x + 1}{2x - 5}$. Find $f'(3)$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Apply quotient rule.\n\n$$f'(x) = \\dfrac{3(2x - 5) - (3x + 1)(2)}{(2x - 5)^2} = \\dfrac{6x - 15 - 6x - 2}{(2x - 5)^2} = \\dfrac{-17}{(2x - 5)^2}.$$\n\n**Step 2 (1 mark):** Substitute $x = 3$.\n\n$$f'(3) = \\dfrac{-17}{(6 - 5)^2}.$$\n\n**Step 3 (1 mark):** Simplify.\n\n$$f'(3) = -17.$$", subtopicSlugs: S },
    { content: "Find $\\dfrac{dy}{dx}$ if $y = \\dfrac{\\sin x}{1 + \\cos x}$.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Apply quotient rule.\n\n$$\\dfrac{dy}{dx} = \\dfrac{\\cos x(1 + \\cos x) - \\sin x(-\\sin x)}{(1 + \\cos x)^2}.$$\n\n**Step 2 (1 mark):** Expand the numerator.\n\n$$= \\dfrac{\\cos x + \\cos^2 x + \\sin^2 x}{(1 + \\cos x)^2}.$$\n\n**Step 3 (1 mark):** Use $\\sin^2 x + \\cos^2 x = 1$.\n\n$$= \\dfrac{\\cos x + 1}{(1 + \\cos x)^2}.$$\n\n**Step 4 (1 mark):** Simplify.\n\n$$\\dfrac{dy}{dx} = \\dfrac{1}{1 + \\cos x}.$$", subtopicSlugs: S },
    { content: "A rectangle has length $(t + 3)$ m and width $(t)$ m at time $t > 0$. Find the rate of change of the ratio $\\dfrac{\\text{length}}{\\text{width}}$ at $t = 3$.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Let $r(t) = \\dfrac{t + 3}{t}$. Apply quotient rule.\n\n$$r'(t) = \\dfrac{1 \\cdot t - (t + 3) \\cdot 1}{t^2} = \\dfrac{-3}{t^2}.$$\n\n**Step 2 (1 mark):** Substitute $t = 3$.\n\n$$r'(3) = \\dfrac{-3}{9}.$$\n\n**Step 3 (1 mark):** Simplify.\n\n$$r'(3) = -\\dfrac{1}{3}.$$", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "Let $f(x) = \\dfrac{x}{x^2 + 4}$.\n\n**a.** Find $f'(x)$ using the quotient rule. (3 marks)\n\n**b.** Find the stationary points of $f$. (3 marks)\n\n**c.** Classify each stationary point. (3 marks)\n\n**d.** Evaluate $f(0)$ and describe the behaviour as $x \\to \\infty$. (2 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* Let $u = x$, $v = x^2 + 4$. Apply quotient rule.\n\n$$f'(x) = \\dfrac{1 \\cdot (x^2 + 4) - x(2x)}{(x^2 + 4)^2}.$$\n\n*Step 2 (1 mark):* Expand numerator.\n\n$$= \\dfrac{x^2 + 4 - 2x^2}{(x^2 + 4)^2}.$$\n\n*Step 3 (1 mark):* Simplify.\n\n$$f'(x) = \\dfrac{4 - x^2}{(x^2 + 4)^2}.$$\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Set $f'(x) = 0$: need $4 - x^2 = 0$.\n\n*Step 2 (1 mark):* $x = \\pm 2$.\n\n*Step 3 (1 mark):* $f(2) = \\dfrac{2}{8} = \\tfrac{1}{4}$; $f(-2) = -\\tfrac{1}{4}$. Stationary points at $(2, 1/4)$ and $(-2, -1/4)$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Check sign of $f'$ around $x = 2$: for $x$ slightly less than $2$, $4 - x^2 > 0$; slightly more, $< 0$. So local maximum at $(2, 1/4)$.\n\n*Step 2 (1 mark):* Similarly at $x = -2$: slightly less, $4 - x^2 < 0$; slightly more, $> 0$. Local minimum at $(-2, -1/4)$.\n\n*Step 3 (1 mark):* State: max $(2, 1/4)$, min $(-2, -1/4)$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $f(0) = 0$.\n\n*Step 2 (1 mark):* As $x \\to \\infty$, $f(x) \\to 0$ since denominator grows faster than numerator.", subtopicSlugs: S },
    { content: "Consider $g(x) = \\dfrac{\\ln x}{x}$ for $x > 0$.\n\n**a.** Find $g'(x)$. (2 marks)\n\n**b.** Find the stationary point of $g$. (3 marks)\n\n**c.** Classify the stationary point. (2 marks)\n\n**d.** Compute $g(1)$ and the equation of the tangent to $y = g(x)$ at $x = 1$. (3 marks)", marks: 10, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Apply quotient rule.\n\n$$g'(x) = \\dfrac{(1/x) x - \\ln x \\cdot 1}{x^2}.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$g'(x) = \\dfrac{1 - \\ln x}{x^2}.$$\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Set $g'(x) = 0$: $1 - \\ln x = 0$.\n\n*Step 2 (1 mark):* Solve: $\\ln x = 1$, so $x = e$.\n\n*Step 3 (1 mark):* $g(e) = \\dfrac{1}{e}$. Stationary point $(e, 1/e)$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* For $x$ slightly less than $e$, $1 - \\ln x > 0$ so $g' > 0$.\n\n*Step 2 (1 mark):* For $x$ slightly more, $g' < 0$. Local maximum at $(e, 1/e)$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $g(1) = 0$.\n\n*Step 2 (1 mark):* $g'(1) = \\dfrac{1 - 0}{1} = 1$.\n\n*Step 3 (1 mark):* Tangent: $y = x - 1$.", subtopicSlugs: S },
    { content: "Let $f(x) = \\dfrac{e^x}{x}$ for $x > 0$.\n\n**a.** Find $f'(x)$. (2 marks)\n\n**b.** Find the value of $x$ that minimises $f$ on $(0, \\infty)$. (3 marks)\n\n**c.** State the minimum value of $f$. (2 marks)\n\n**d.** Describe the behaviour of $f$ as $x \\to 0^+$ and as $x \\to \\infty$. (2 marks)\n\n**e.** Find the tangent to $y = f(x)$ at $x = 1$. (3 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Apply quotient rule.\n\n$$f'(x) = \\dfrac{e^x \\cdot x - e^x \\cdot 1}{x^2}.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$f'(x) = \\dfrac{e^x(x - 1)}{x^2}.$$\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Set $f'(x) = 0$. Since $e^x > 0$ and $x > 0$, need $x - 1 = 0$.\n\n*Step 2 (1 mark):* So $x = 1$.\n\n*Step 3 (1 mark):* For $x < 1$, $f' < 0$; for $x > 1$, $f' > 0$ — confirming minimum.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Evaluate $f(1) = e/1$.\n\n*Step 2 (1 mark):* Minimum value is $e$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* As $x \\to 0^+$, $f(x) = e^x / x \\to \\infty$.\n\n*Step 2 (1 mark):* As $x \\to \\infty$, $f(x) \\to \\infty$ (exponential dominates).\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* $f(1) = e$.\n\n*Step 2 (1 mark):* $f'(1) = 0$ (horizontal tangent).\n\n*Step 3 (1 mark):* Tangent: $y = e$.", subtopicSlugs: S },
    { content: "Let $h(x) = \\dfrac{x^2 - 4}{x^2 + 4}$.\n\n**a.** Find $h'(x)$. (3 marks)\n\n**b.** Find the stationary point of $h$. (2 marks)\n\n**c.** Classify the stationary point. (2 marks)\n\n**d.** Find $h(0)$, $h(2)$, and $h(-2)$. (2 marks)\n\n**e.** Describe $h$ as $x \\to \\pm \\infty$. (2 marks)\n\n**f.** Find the $x$-intercepts. (2 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* Apply quotient rule with $u = x^2 - 4$, $v = x^2 + 4$.\n\n$$h'(x) = \\dfrac{2x(x^2 + 4) - (x^2 - 4)(2x)}{(x^2 + 4)^2}.$$\n\n*Step 2 (1 mark):* Expand the numerator.\n\n$$= \\dfrac{2x[(x^2 + 4) - (x^2 - 4)]}{(x^2 + 4)^2}.$$\n\n*Step 3 (1 mark):* Simplify.\n\n$$h'(x) = \\dfrac{16x}{(x^2 + 4)^2}.$$\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Set numerator to zero.\n\n$$16x = 0 \\implies x = 0.$$\n\n*Step 2 (1 mark):* $h(0) = -1$. Stationary point $(0, -1)$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* For $x < 0$, $h' < 0$; for $x > 0$, $h' > 0$.\n\n*Step 2 (1 mark):* So $(0, -1)$ is a local (and global) minimum.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $h(0) = -1$.\n\n*Step 2 (1 mark):* $h(2) = 0/8 = 0$; $h(-2) = 0$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Divide: $h(x) = 1 - \\dfrac{8}{x^2 + 4}$.\n\n*Step 2 (1 mark):* As $x \\to \\pm \\infty$, $h(x) \\to 1$ (horizontal asymptote).\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $h(x) = 0$ iff $x^2 - 4 = 0$.\n\n*Step 2 (1 mark):* $x = \\pm 2$.", subtopicSlugs: S },
    { content: "A tank's water level at time $t$ minutes is $L(t) = \\dfrac{20 t}{t + 5}$ cm.\n\n**a.** Find $L(0)$, $L(5)$, and $L(15)$. (3 marks)\n\n**b.** Find $L'(t)$ using the quotient rule. (3 marks)\n\n**c.** Evaluate $L'(0)$ and $L'(5)$. (2 marks)\n\n**d.** Determine what $L(t)$ approaches as $t \\to \\infty$. (2 marks)\n\n**e.** Find the time at which the water level is $10$ cm. (3 marks)\n\n**f.** At this time, what is the rate of increase of the water level? (2 marks)", marks: 15, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* $L(0) = 0$.\n\n*Step 2 (1 mark):* $L(5) = \\dfrac{100}{10} = 10$ cm.\n\n*Step 3 (1 mark):* $L(15) = \\dfrac{300}{20} = 15$ cm.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Apply quotient rule with $u = 20t$, $v = t + 5$.\n\n$$L'(t) = \\dfrac{20(t + 5) - 20t \\cdot 1}{(t + 5)^2}.$$\n\n*Step 2 (1 mark):* Expand numerator.\n\n$$= \\dfrac{20t + 100 - 20t}{(t + 5)^2}.$$\n\n*Step 3 (1 mark):* Simplify.\n\n$$L'(t) = \\dfrac{100}{(t + 5)^2}.$$\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $L'(0) = \\dfrac{100}{25} = 4$ cm/min.\n\n*Step 2 (1 mark):* $L'(5) = \\dfrac{100}{100} = 1$ cm/min.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Divide top and bottom by $t$: $L(t) = \\dfrac{20}{1 + 5/t}$.\n\n*Step 2 (1 mark):* As $t \\to \\infty$, $L(t) \\to 20$ cm.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* Set $L(t) = 10$: $\\dfrac{20 t}{t + 5} = 10$.\n\n*Step 2 (1 mark):* Cross-multiply.\n\n$$20 t = 10(t + 5) = 10 t + 50.$$\n\n*Step 3 (1 mark):* Solve.\n\n$$10 t = 50 \\implies t = 5 \\text{ minutes}.$$\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* Use $t = 5$ from part e.\n\n*Step 2 (1 mark):* $L'(5) = 1$ cm/min (from part c).", subtopicSlugs: S },
  ];
  writeQset(OUT("quotient-rule"), { mcq, shortAnswer, extendedResponse });
}

