{
  const S = ["antidifferentiation"];
  const mcq: MCQ[] = [
    { content: "$\\int x^3 \\, dx$ equals:", optionA: "$\\dfrac{x^4}{4} + C$", optionB: "$3 x^2 + C$", optionC: "$4 x^4 + C$", optionD: "$\\dfrac{x^2}{2} + C$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Power rule: $\\int x^n dx = \\dfrac{x^{n+1}}{n+1} + C$ for $n \\neq -1$. With $n = 3$, the answer is $\\dfrac{x^4}{4} + C$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "$\\int 6 x \\, dx$ equals:", optionA: "$3 x^2 + C$", optionB: "$6 + C$", optionC: "$6 x^2 + C$", optionD: "$\\dfrac{6 x^2}{2} + C$... same as A", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\int 6 x \\, dx = 6 \\cdot \\dfrac{x^2}{2} + C = 3 x^2 + C$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "$\\int e^x \\, dx$ equals:", optionA: "$x e^{x-1} + C$", optionB: "$e^x + C$", optionC: "$e^x \\ln x + C$", optionD: "$\\dfrac{e^x}{x} + C$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\int e^x dx = e^x + C$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "$\\int \\cos x \\, dx$ equals:", optionA: "$-\\sin x + C$", optionB: "$\\sin x + C$", optionC: "$-\\cos x + C$", optionD: "$\\tan x + C$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\int \\cos x \\, dx = \\sin x + C$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "$\\int \\dfrac{1}{x} \\, dx$ (for $x > 0$) equals:", optionA: "$\\ln|x| + C$", optionB: "$-\\dfrac{1}{x^2} + C$", optionC: "$\\dfrac{x}{2} + C$", optionD: "$x^{-2} + C$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Special case: $\\int x^{-1} dx = \\ln|x| + C$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "$\\int \\sin x \\, dx$ equals:", optionA: "$\\cos x + C$", optionB: "$-\\cos x + C$", optionC: "$-\\sin x + C$", optionD: "$\\sec x + C$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\int \\sin x \\, dx = -\\cos x + C$.\n\n**Answer: B**", subtopicSlugs: S },
    // Medium
    { content: "$\\int (2 x^3 - 5 x) \\, dx$ equals:", optionA: "$\\dfrac{x^4}{2} - \\dfrac{5 x^2}{2} + C$", optionB: "$2 x^4 - 5 x^2 + C$", optionC: "$6 x^2 - 5 + C$", optionD: "$x^4 - 5 x + C$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Integrate term by term: $\\dfrac{2 x^4}{4} - \\dfrac{5 x^2}{2} + C = \\dfrac{x^4}{2} - \\dfrac{5 x^2}{2} + C$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "$\\int 4 e^{2x} \\, dx$ equals:", optionA: "$2 e^{2x} + C$", optionB: "$8 e^{2x} + C$", optionC: "$4 e^{2x} + C$", optionD: "$e^{2x} + C$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\int e^{ax} dx = \\dfrac{1}{a} e^{ax}$. So $\\int 4 e^{2x} dx = 4 \\cdot \\dfrac{1}{2} e^{2x} + C = 2 e^{2x} + C$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "$\\int \\sin(3 x) \\, dx$ equals:", optionA: "$-\\dfrac{1}{3}\\cos(3x) + C$", optionB: "$\\dfrac{1}{3}\\cos(3x) + C$", optionC: "$-3 \\cos(3 x) + C$", optionD: "$3\\cos(3x) + C$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\int \\sin(a x) dx = -\\dfrac{1}{a} \\cos(a x)$. With $a = 3$: $-\\dfrac{1}{3}\\cos(3x) + C$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f'(x) = 3 x^2 - 2$ and $f(1) = 5$, then $f(x)$ equals:", optionA: "$x^3 - 2x + 5$", optionB: "$x^3 - 2x + 6$", optionC: "$x^3 - 2x + 4$", optionD: "$x^3 - 2x$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f(x) = x^3 - 2 x + C$. Apply $f(1) = 1 - 2 + C = -1 + C = 5$, so $C = 6$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "$\\int \\cos(2 x + 1) \\, dx$ equals:", optionA: "$\\dfrac{1}{2}\\sin(2x+1) + C$", optionB: "$\\sin(2x+1) + C$", optionC: "$-\\dfrac{1}{2}\\sin(2x+1) + C$", optionD: "$2\\sin(2x+1) + C$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\int \\cos(ax + b) dx = \\dfrac{1}{a}\\sin(ax + b) + C$. With $a = 2$: $\\dfrac{1}{2}\\sin(2x + 1) + C$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: `The graph of $f'(x) = 2x$ is shown.\n\n${graphImage((x) => 2 * x, { xMin: -3, xMax: 3, yMin: -6, yMax: 6, marks: [{ x: 0, y: 0 }] }, "Graph y=2x")}\n\nIf $f(0) = 3$, then $f(x)$ equals:`, optionA: "$x^2 + 3$", optionB: "$x^2 - 3$", optionC: "$2 x^2 + 3$", optionD: "$x^2$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f(x) = x^2 + C$. From $f(0) = 3$, $C = 3$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "$\\int \\dfrac{2}{x} \\, dx$ equals:", optionA: "$2 \\ln|x| + C$", optionB: "$\\ln|2 x| + C$", optionC: "$\\dfrac{2}{x^2} + C$", optionD: "$2 \\ln(2 x) + C$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\int \\dfrac{2}{x} dx = 2 \\ln|x| + C$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "$\\int \\sqrt{x} \\, dx$ equals:", optionA: "$\\dfrac{2}{3} x^{3/2} + C$", optionB: "$\\dfrac{1}{2\\sqrt{x}} + C$", optionC: "$\\dfrac{3}{2} x^{3/2} + C$", optionD: "$x^{3/2} + C$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\int x^{1/2} dx = \\dfrac{x^{3/2}}{3/2} + C = \\dfrac{2}{3} x^{3/2} + C$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "$\\int e^{-x} \\, dx$ equals:", optionA: "$e^{-x} + C$", optionB: "$-e^{-x} + C$", optionC: "$-\\ln|x| + C$", optionD: "$\\dfrac{1}{e^x} \\ln x + C$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $\\int e^{ax} dx = \\dfrac{1}{a} e^{ax}$. With $a = -1$: $-e^{-x} + C$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f'(x) = \\cos x$ and $f(\\pi/2) = 3$, then $f(x)$ equals:", optionA: "$\\sin x + 2$", optionB: "$\\sin x + 3$", optionC: "$\\sin x$", optionD: "$-\\cos x + 3$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f(x) = \\sin x + C$. Apply $f(\\pi/2) = 1 + C = 3$, so $C = 2$.\n\n**Answer: A**", subtopicSlugs: S },
    // Hard
    { content: "$\\int (x + 1)^3 \\, dx$ equals:", optionA: "$\\dfrac{(x+1)^4}{4} + C$", optionB: "$3(x+1)^2 + C$", optionC: "$(x+1)^4 + C$", optionD: "$\\dfrac{x^4}{4} + x + C$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Let $u = x + 1$, $du = dx$. $\\int u^3 du = u^4/4 + C = (x+1)^4/4 + C$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The antiderivative of $f(x) = 3 e^{3x}$ is:", optionA: "$e^{3x} + C$", optionB: "$3 e^{3x} + C$", optionC: "$9 e^{3x} + C$", optionD: "$\\dfrac{e^{3x}}{3} + C$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\int 3 e^{3x} dx = 3 \\cdot \\dfrac{1}{3} e^{3x} + C = e^{3x} + C$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "$\\int \\dfrac{1}{2x - 3} \\, dx$ equals:", optionA: "$\\ln|2x - 3| + C$", optionB: "$\\dfrac{1}{2}\\ln|2x - 3| + C$", optionC: "$2 \\ln|2x - 3| + C$", optionD: "$\\dfrac{\\ln(2x - 3)}{2} + C$ only", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $\\int \\dfrac{1}{ax + b} dx = \\dfrac{1}{a}\\ln|ax + b| + C$. With $a = 2$: $\\dfrac{1}{2}\\ln|2x - 3| + C$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A car's acceleration is $a(t) = 2 t$ m/s$^2$ and velocity $v(0) = 5$ m/s. The velocity function is:", optionA: "$t^2 + 5$", optionB: "$t^2 + 5 t$", optionC: "$2 t + 5$", optionD: "$t^2 - 5$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $v(t) = \\int 2 t \\, dt = t^2 + C$. From $v(0) = 5$: $C = 5$. So $v(t) = t^2 + 5$.\n\n**Answer: A**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "Find $\\int (4 x^3 - 6 x + 2) \\, dx$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Integrate term by term.\n\n$$\\int 4 x^3 dx - \\int 6 x \\, dx + \\int 2 \\, dx.$$\n\n**Step 2 (1 mark):** Evaluate.\n\n$$= x^4 - 3 x^2 + 2 x + C.$$", subtopicSlugs: S },
    { content: "Find $\\int e^{5 x} \\, dx$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Use $\\int e^{ax} dx = \\dfrac{1}{a} e^{ax} + C$.\n\n**Step 2 (1 mark):** With $a = 5$.\n\n$$\\int e^{5 x} dx = \\dfrac{1}{5} e^{5 x} + C.$$", subtopicSlugs: S },
    { content: "Find $\\int \\sin(2 x) \\, dx$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $\\int \\sin(ax) dx = -\\dfrac{1}{a}\\cos(ax)$.\n\n**Step 2 (1 mark):** With $a = 2$.\n\n$$\\int \\sin(2x) dx = -\\dfrac{1}{2}\\cos(2x) + C.$$", subtopicSlugs: S },
    { content: "Given $f'(x) = 3 x^2 + 4 x$ and $f(0) = 2$, find $f(x)$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Antidifferentiate.\n\n$$f(x) = x^3 + 2 x^2 + C.$$\n\n**Step 2 (1 mark):** Apply initial condition.\n\n$$f(0) = C = 2.$$\n\n**Step 3 (1 mark):** Final answer.\n\n$$f(x) = x^3 + 2 x^2 + 2.$$", subtopicSlugs: S },
    { content: "Find $\\int \\left(\\dfrac{1}{x^2} + 2\\sqrt{x}\\right) dx$ (for $x > 0$).", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Rewrite as $x^{-2} + 2 x^{1/2}$.\n\n**Step 2 (1 mark):** Integrate each.\n\n$$\\int x^{-2} dx = -x^{-1}, \\quad \\int 2 x^{1/2} dx = \\dfrac{4}{3} x^{3/2}.$$\n\n**Step 3 (1 mark):** Combine.\n\n$$-\\dfrac{1}{x} + \\dfrac{4}{3} x^{3/2} + C.$$", subtopicSlugs: S },
    { content: "A particle has acceleration $a(t) = 6 t - 4$ m/s$^2$, with $v(0) = 2$ m/s and $s(0) = 0$. Find $s(t)$.", marks: 4, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Integrate $a$ to get velocity.\n\n$$v(t) = 3 t^2 - 4 t + C_1.$$\n\n**Step 2 (1 mark):** $v(0) = 2$ gives $C_1 = 2$, so $v(t) = 3 t^2 - 4 t + 2$.\n\n**Step 3 (1 mark):** Integrate $v$ to get position.\n\n$$s(t) = t^3 - 2 t^2 + 2 t + C_2.$$\n\n**Step 4 (1 mark):** $s(0) = 0$ gives $C_2 = 0$, so $s(t) = t^3 - 2 t^2 + 2 t$.", subtopicSlugs: S },
    { content: "Find $\\int (e^{2 x} + 3\\cos x) \\, dx$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Integrate the exponential term.\n\n$$\\int e^{2 x} dx = \\dfrac{1}{2} e^{2 x}.$$\n\n**Step 2 (1 mark):** Integrate the cosine term.\n\n$$\\int 3 \\cos x \\, dx = 3 \\sin x.$$\n\n**Step 3 (1 mark):** Combine.\n\n$$\\dfrac{1}{2} e^{2 x} + 3\\sin x + C.$$", subtopicSlugs: S },
    { content: "Find $f(x)$ given $f'(x) = \\dfrac{2}{x}$ (for $x > 0$) and $f(1) = 3$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Antidifferentiate.\n\n$$f(x) = 2 \\ln x + C.$$\n\n**Step 2 (1 mark):** Apply $f(1) = 0 + C = 3$, so $C = 3$.\n\n**Step 3 (1 mark):** Final.\n\n$$f(x) = 2 \\ln x + 3.$$", subtopicSlugs: S },
    { content: "Find $\\int (2 x - 1)^5 dx$.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Let $u = 2 x - 1$, $du = 2\\, dx$, so $dx = du/2$.\n\n**Step 2 (1 mark):** Substitute.\n\n$$\\int u^5 \\cdot \\dfrac{du}{2} = \\dfrac{1}{2} \\cdot \\dfrac{u^6}{6}.$$\n\n**Step 3 (1 mark):** Simplify.\n\n$$= \\dfrac{u^6}{12}.$$\n\n**Step 4 (1 mark):** Substitute back.\n\n$$= \\dfrac{(2 x - 1)^6}{12} + C.$$", subtopicSlugs: S },
    { content: "Given $\\dfrac{dy}{dx} = \\dfrac{1}{x + 2}$ and $y = 0$ when $x = -1$, find $y$ in terms of $x$.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Antidifferentiate.\n\n$$y = \\ln|x + 2| + C.$$\n\n**Step 2 (1 mark):** Apply $y(-1) = \\ln 1 + C = C = 0$.\n\n**Step 3 (1 mark):** So $y = \\ln|x + 2|$.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "A particle moves with acceleration $a(t) = 6 t - 12$ m/s$^2$ for $t \\geq 0$. At $t = 0$, the velocity is $v(0) = 5$ m/s and the position is $s(0) = 0$.\n\n**a.** Find the velocity $v(t)$. (3 marks)\n\n**b.** Find the position $s(t)$. (3 marks)\n\n**c.** Find the time(s) when the particle is at rest. (3 marks)\n\n**d.** Find the position of the particle at the first time it is at rest. (2 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* Antidifferentiate $a$.\n\n$$v(t) = 3 t^2 - 12 t + C_1.$$\n\n*Step 2 (1 mark):* Apply $v(0) = 5$.\n\n$$C_1 = 5.$$\n\n*Step 3 (1 mark):* State $v(t) = 3 t^2 - 12 t + 5$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Antidifferentiate $v$.\n\n$$s(t) = t^3 - 6 t^2 + 5 t + C_2.$$\n\n*Step 2 (1 mark):* Apply $s(0) = 0$.\n\n$$C_2 = 0.$$\n\n*Step 3 (1 mark):* State $s(t) = t^3 - 6 t^2 + 5 t$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Set $v(t) = 0$.\n\n$$3 t^2 - 12 t + 5 = 0.$$\n\n*Step 2 (1 mark):* Apply quadratic formula.\n\n$$t = \\dfrac{12 \\pm \\sqrt{144 - 60}}{6} = \\dfrac{12 \\pm \\sqrt{84}}{6}.$$\n\n*Step 3 (1 mark):* Simplify.\n\n$$t = \\dfrac{6 \\pm \\sqrt{21}}{3}.$$\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* The first rest time is $t_1 = \\dfrac{6 - \\sqrt{21}}{3}$.\n\n*Step 2 (1 mark):* Substitute into $s(t)$ (leave in exact form).\n\n$$s(t_1) = t_1^3 - 6 t_1^2 + 5 t_1.$$", subtopicSlugs: S },
    { content: "Let $f'(x) = 6 x^2 + 2 x - 4$ and $f(0) = 1$.\n\n**a.** Find $f(x)$. (3 marks)\n\n**b.** Evaluate $f(2)$. (2 marks)\n\n**c.** Find all values of $x$ where $f'(x) = 0$. (3 marks)\n\n**d.** Classify the stationary points using the sign of $f'$. (2 marks)", marks: 10, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* Antidifferentiate.\n\n$$f(x) = 2 x^3 + x^2 - 4 x + C.$$\n\n*Step 2 (1 mark):* Apply $f(0) = C = 1$.\n\n*Step 3 (1 mark):* State $f(x) = 2 x^3 + x^2 - 4 x + 1$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Substitute $x = 2$.\n\n$$f(2) = 16 + 4 - 8 + 1.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$f(2) = 13.$$\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Set $6 x^2 + 2 x - 4 = 0$.\n\n*Step 2 (1 mark):* Divide by $2$: $3 x^2 + x - 2 = 0$.\n\n*Step 3 (1 mark):* Factor: $(3 x - 2)(x + 1) = 0$, so $x = 2/3$ or $x = -1$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* At $x = -1$: $f'$ changes from $+$ to $-$, so local max.\n\n*Step 2 (1 mark):* At $x = 2/3$: $f'$ changes from $-$ to $+$, so local min.", subtopicSlugs: S },
    { content: "A water tank is being filled such that the rate of change of volume is $\\dfrac{dV}{dt} = 3 t^2 + 2 t$ litres per minute.\n\n**a.** Find $V(t)$ given $V(0) = 0$. (3 marks)\n\n**b.** Compute the volume of water at $t = 4$ min. (2 marks)\n\n**c.** Find the average rate of change of volume from $t = 0$ to $t = 4$. (3 marks)\n\n**d.** At what time does the rate of change of volume equal $24$ L/min? (3 marks)\n\n**e.** Compute $V(t)$ at that time. (2 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* Antidifferentiate.\n\n$$V(t) = t^3 + t^2 + C.$$\n\n*Step 2 (1 mark):* Apply $V(0) = C = 0$.\n\n*Step 3 (1 mark):* $V(t) = t^3 + t^2$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Substitute $t = 4$.\n\n$$V(4) = 64 + 16.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$V(4) = 80 \\text{ L}.$$\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Average rate $= \\dfrac{V(4) - V(0)}{4 - 0}$.\n\n*Step 2 (1 mark):* Substitute values.\n\n$$= \\dfrac{80 - 0}{4}.$$\n\n*Step 3 (1 mark):* Simplify.\n\n$$= 20 \\text{ L/min}.$$\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* Set $3 t^2 + 2 t = 24$.\n\n*Step 2 (1 mark):* Rearrange.\n\n$$3 t^2 + 2 t - 24 = 0.$$\n\n*Step 3 (1 mark):* Solve (quadratic formula): $t = \\dfrac{-2 + \\sqrt{4 + 288}}{6} = \\dfrac{-2 + \\sqrt{292}}{6} \\approx 2.52$ min. (Take positive root.)\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Use $t \\approx 2.52$.\n\n*Step 2 (1 mark):* $V \\approx 2.52^3 + 2.52^2 \\approx 16.0 + 6.35 \\approx 22.35$ L.", subtopicSlugs: S },
    { content: "Consider $f'(x) = \\cos(2 x) + \\sin x$.\n\n**a.** Find $f(x)$ given $f(0) = 1$. (4 marks)\n\n**b.** Find $f(\\pi/2)$. (3 marks)\n\n**c.** Find $f'(\\pi/2)$. (2 marks)\n\n**d.** Find the values of $x$ in $[0, 2\\pi]$ where $f'(x) = 1$. (3 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (4 marks)**\n\n*Step 1 (1 mark):* Antidifferentiate $\\cos(2x)$.\n\n$$\\int \\cos(2x) dx = \\dfrac{1}{2}\\sin(2 x).$$\n\n*Step 2 (1 mark):* Antidifferentiate $\\sin x$.\n\n$$\\int \\sin x \\, dx = -\\cos x.$$\n\n*Step 3 (1 mark):* Combine.\n\n$$f(x) = \\dfrac{1}{2}\\sin(2 x) - \\cos x + C.$$\n\n*Step 4 (1 mark):* Apply $f(0) = 0 - 1 + C = 1$, so $C = 2$.\n\n$$f(x) = \\dfrac{1}{2}\\sin(2 x) - \\cos x + 2.$$\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Compute $\\sin(\\pi) = 0$.\n\n*Step 2 (1 mark):* Compute $\\cos(\\pi/2) = 0$.\n\n*Step 3 (1 mark):* $f(\\pi/2) = 0 - 0 + 2 = 2$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $f'(\\pi/2) = \\cos \\pi + \\sin(\\pi/2)$.\n\n*Step 2 (1 mark):* Simplify: $-1 + 1 = 0$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* Set $\\cos(2 x) + \\sin x = 1$.\n\n*Step 2 (1 mark):* Use $\\cos(2x) = 1 - 2\\sin^2 x$: $1 - 2\\sin^2 x + \\sin x = 1$, so $\\sin x(1 - 2\\sin x) = 0$.\n\n*Step 3 (1 mark):* Solutions: $\\sin x = 0 \\Rightarrow x = 0, \\pi, 2\\pi$; $\\sin x = 1/2 \\Rightarrow x = \\pi/6, 5\\pi/6$.", subtopicSlugs: S },
    { content: "A rocket's vertical acceleration is $a(t) = 10 - t$ m/s$^2$ for $0 \\leq t \\leq 10$ s. The initial velocity is $v(0) = 0$ and initial height is $s(0) = 0$.\n\n**a.** Find $v(t)$. (2 marks)\n\n**b.** Find the time at which the rocket reaches maximum velocity. (2 marks)\n\n**c.** State the maximum velocity. (1 mark)\n\n**d.** Find $s(t)$. (2 marks)\n\n**e.** Find the height at $t = 10$. (2 marks)\n\n**f.** Describe what happens to the rocket's velocity as $t \\to 10$. (2 marks)\n\n**g.** Find the time at which the rocket is at height $50$ m. (2 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Antidifferentiate.\n\n$$v(t) = 10 t - \\dfrac{t^2}{2} + C.$$\n\n*Step 2 (1 mark):* Apply $v(0) = C = 0$. So $v(t) = 10 t - \\dfrac{t^2}{2}$.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Set $v'(t) = 10 - t = 0$.\n\n*Step 2 (1 mark):* $t = 10$ s.\n\n**c. (1 mark)**\n\n*Step 1 (1 mark):* $v(10) = 100 - 50 = 50$ m/s.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Antidifferentiate $v$.\n\n$$s(t) = 5 t^2 - \\dfrac{t^3}{6} + C_2.$$\n\n*Step 2 (1 mark):* Apply $s(0) = C_2 = 0$. So $s(t) = 5 t^2 - \\dfrac{t^3}{6}$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $s(10) = 500 - \\dfrac{1000}{6}$.\n\n*Step 2 (1 mark):* Simplify: $= \\dfrac{3000 - 1000}{6} = \\dfrac{2000}{6} = \\dfrac{1000}{3} \\approx 333.3$ m.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* At $t = 10$, $v'(10) = 0$.\n\n*Step 2 (1 mark):* Velocity is at its maximum ($50$ m/s) — about to start decreasing (if the model extends).\n\n**g. (2 marks)**\n\n*Step 1 (1 mark):* Set $5 t^2 - t^3/6 = 50$.\n\n*Step 2 (1 mark):* Multiply by $6$: $30 t^2 - t^3 = 300$, so $t^3 - 30 t^2 + 300 = 0$. Numerical solve: $t \\approx 3.53$ s.", subtopicSlugs: S },
  ];
  writeQset(OUT("antidifferentiation"), { mcq, shortAnswer, extendedResponse });
}

