{
  const S = ["rates-of-change"];
  const mcq: MCQ[] = [
    { content: "If $s(t) = t^2 + 3 t$ gives position in metres, the velocity at $t = 2$ is:", optionA: "$4$", optionB: "$5$", optionC: "$7$", optionD: "$10$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Velocity $= s'(t) = 2 t + 3$. At $t = 2$: $2(2) + 3 = 7$ m/s.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The rate of change of $y = 3 x^2$ with respect to $x$ when $x = 4$ is:", optionA: "$12$", optionB: "$24$", optionC: "$48$", optionD: "$6$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $dy/dx = 6 x$. At $x = 4$: $24$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If the area of a circle is $A = \\pi r^2$, then $dA/dr$ at $r = 2$ equals:", optionA: "$4\\pi$", optionB: "$2\\pi$", optionC: "$8\\pi$", optionD: "$\\pi$", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $dA/dr = 2\\pi r$. At $r = 2$: $4\\pi$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $V = \\dfrac{4}{3}\\pi r^3$ and $r = 3$, then $dV/dr$ equals:", optionA: "$12\\pi$", optionB: "$36\\pi$", optionC: "$108\\pi$", optionD: "$9\\pi$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $dV/dr = 4 \\pi r^2$. At $r = 3$: $36\\pi$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "Average rate of change of $f(x) = x^2$ on $[1, 3]$ is:", optionA: "$2$", optionB: "$4$", optionC: "$6$", optionD: "$9$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Average rate $= \\dfrac{f(3) - f(1)}{3 - 1} = \\dfrac{9 - 1}{2} = 4$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A particle has position $s(t) = 5 t^2$. Its instantaneous velocity at $t = 2$ is:", optionA: "$5$", optionB: "$10$", optionC: "$20$", optionD: "$50$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $v = s' = 10 t$. At $t = 2$: $20$.\n\n**Answer: C**", subtopicSlugs: S },
    // Medium
    { content: "Water is poured into a tank such that its volume is $V(t) = 2 t^3 + 5 t$ litres at time $t$ min. At $t = 3$, the rate of filling is:", optionA: "$59$ L/min", optionB: "$23$ L/min", optionC: "$53$ L/min", optionD: "$61$ L/min", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $V'(t) = 6 t^2 + 5$. At $t = 3$: $54 + 5 = 59$ L/min.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "A balloon's volume is $V = \\dfrac{4}{3}\\pi r^3$. If $r$ is increasing at $2$ cm/s when $r = 5$, then $dV/dt$ is:", optionA: "$50 \\pi$ cm$^3$/s", optionB: "$100 \\pi$ cm$^3$/s", optionC: "$200 \\pi$ cm$^3$/s", optionD: "$400 \\pi$ cm$^3$/s", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Chain rule: $dV/dt = (dV/dr)(dr/dt) = 4\\pi r^2 \\cdot 2 = 8\\pi r^2$. At $r = 5$: $200 \\pi$ cm$^3$/s.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The height of a projectile is $h(t) = -5 t^2 + 20 t$ m. The maximum height occurs at:", optionA: "$t = 1$ s", optionB: "$t = 2$ s", optionC: "$t = 3$ s", optionD: "$t = 4$ s", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $h'(t) = -10 t + 20 = 0$ gives $t = 2$ s.\n\n**Answer: B**", subtopicSlugs: S },
    { content: `The height of a curve $y = -t^2 + 6 t$ (position vs time) is shown.\n\n${graphImage((x) => -x * x + 6 * x, { xMin: 0, xMax: 6, yMin: -1, yMax: 10, marks: [{ x: 3, y: 9, label: "max" }] }, "Graph y=-t^2+6t")}\n\nThe instantaneous velocity at $t = 1$ is:`, optionA: "$2$", optionB: "$4$", optionC: "$6$", optionD: "$-2$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y' = -2 t + 6$. At $t = 1$: $4$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $P(t) = 500 e^{0.1 t}$, then the rate of growth $dP/dt$ at $t = 0$ is:", optionA: "$50$", optionB: "$500$", optionC: "$5$", optionD: "$100$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $dP/dt = 500 \\cdot 0.1 e^{0.1 t} = 50 e^{0.1 t}$. At $t = 0$: $50$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "A square has side length $s$ increasing at $3$ cm/s. When $s = 4$ cm, the rate of change of area is:", optionA: "$8$ cm$^2$/s", optionB: "$12$ cm$^2$/s", optionC: "$24$ cm$^2$/s", optionD: "$32$ cm$^2$/s", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $A = s^2$, $dA/dt = 2 s \\cdot ds/dt = 2(4)(3) = 24$ cm$^2$/s.\n\n**Answer: C**", subtopicSlugs: S },
    { content: `The table shows volumes at times $t$.\n\n| $t$ (s) | $0$ | $1$ | $2$ | $3$ | $4$ |\n|---|---|---|---|---|---|\n| $V$ (L) | $0$ | $2$ | $8$ | $18$ | $32$ |\n\nThe average rate of change of volume on $[0, 4]$ is:`, optionA: "$2$ L/s", optionB: "$4$ L/s", optionC: "$8$ L/s", optionD: "$16$ L/s", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Average rate $= \\dfrac{32 - 0}{4 - 0} = 8$ L/s.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "A particle moves so that $s(t) = t^3 - 3 t^2$. Its acceleration at $t = 2$ is:", optionA: "$6$", optionB: "$0$", optionC: "$12$", optionD: "$-6$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $v = 3 t^2 - 6 t$, $a = 6 t - 6$. At $t = 2$: $6$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "A spherical balloon is being inflated so that its radius is $r = 2 + t/5$ cm at time $t$ seconds. The rate of change of radius is:", optionA: "$1/5$ cm/s", optionB: "$2$ cm/s", optionC: "$5$ cm/s", optionD: "$1$ cm/s", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $dr/dt = 1/5$ cm/s.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The temperature of a cup of coffee is $T(t) = 20 + 80 e^{-t/10}$ °C at time $t$ min. At $t = 0$, the rate of cooling is:", optionA: "$-8$ °C/min", optionB: "$-80$ °C/min", optionC: "$8$ °C/min", optionD: "$0$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $T'(t) = 80 \\cdot (-1/10) e^{-t/10} = -8 e^{-t/10}$. At $t = 0$: $-8$ °C/min.\n\n**Answer: A**", subtopicSlugs: S },
    // Hard
    { content: "A ladder of length $5$ m rests against a wall. The base slides away at $0.5$ m/s. When the base is $3$ m from the wall, the top slides down at:", optionA: "$3/8$ m/s", optionB: "$3/4$ m/s", optionC: "$5/8$ m/s", optionD: "$1/2$ m/s", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $x^2 + y^2 = 25$. Differentiate: $2 x x' + 2 y y' = 0$. At $x = 3$, $y = 4$, $x' = 0.5$: $3(0.5) + 4 y' = 0$, so $y' = -3/8$ m/s. Speed $= 3/8$ m/s.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The side of a cube is increasing at $2$ cm/s. When side is $5$ cm, the rate of change of volume is:", optionA: "$50$ cm$^3$/s", optionB: "$100$ cm$^3$/s", optionC: "$150$ cm$^3$/s", optionD: "$75$ cm$^3$/s", correctOption: "C", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $V = s^3$, $dV/dt = 3 s^2 ds/dt = 3(25)(2) = 150$ cm$^3$/s.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "Water flows into a conical tank (vertex down) at $10$ cm$^3$/s. The tank has height equal to its radius. When the water depth is $h = 4$ cm, the rate of rise is:", optionA: "$\\dfrac{10}{16 \\pi}$ cm/s", optionB: "$\\dfrac{10}{4 \\pi}$ cm/s", optionC: "$\\dfrac{5}{8 \\pi}$ cm/s", optionD: "Both A and C", correctOption: "D", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** For a cone with $r = h$, $V = \\tfrac{1}{3}\\pi h^3$. $dV/dt = \\pi h^2 dh/dt$. At $h = 4$: $10 = \\pi (16) dh/dt$, so $dh/dt = \\dfrac{10}{16\\pi} = \\dfrac{5}{8\\pi}$. Both A and C match.\n\n**Answer: D**", subtopicSlugs: S },
    { content: "A population grows as $P(t) = P_0 e^{kt}$. If $k > 0$, the rate of change $P'$ equals:", optionA: "$k P$", optionB: "$k P_0$", optionC: "$k e^{k t}$", optionD: "$k \\cdot P_0 e^{k t - 1}$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $P'(t) = P_0 \\cdot k e^{kt} = k (P_0 e^{k t}) = k P$.\n\n**Answer: A**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "A particle's position is $s(t) = t^3 - 4 t^2 + 3 t$ metres. Find its velocity at $t = 2$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $v(t) = 3 t^2 - 8 t + 3$.\n\n**Step 2 (1 mark):** At $t = 2$: $v(2) = 12 - 16 + 3 = -1$ m/s.", subtopicSlugs: S },
    { content: "Find the average rate of change of $f(x) = x^3$ on $[1, 4]$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Average rate $= \\dfrac{f(4) - f(1)}{4 - 1} = \\dfrac{64 - 1}{3}$.\n\n**Step 2 (1 mark):** Simplify.\n\n$$= \\dfrac{63}{3} = 21.$$", subtopicSlugs: S },
    { content: "The radius of a circle is increasing at $0.2$ cm/s. Find the rate of change of area when $r = 10$ cm.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $A = \\pi r^2$, so $dA/dt = 2\\pi r \\cdot dr/dt$.\n\n**Step 2 (1 mark):** Substitute $r = 10$, $dr/dt = 0.2$.\n\n$$dA/dt = 2\\pi(10)(0.2).$$\n\n**Step 3 (1 mark):** Simplify.\n\n$$dA/dt = 4\\pi \\text{ cm}^2/\\text{s}.$$", subtopicSlugs: S },
    { content: "A population model is $P(t) = 200 e^{0.05 t}$. Find the rate of growth $P'(t)$ at $t = 10$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $P'(t) = 200 \\cdot 0.05 e^{0.05 t} = 10 e^{0.05 t}$.\n\n**Step 2 (1 mark):** Substitute $t = 10$.\n\n$$P'(10) = 10 e^{0.5}.$$\n\n**Step 3 (1 mark):** Numerical: $10 \\times 1.6487 \\approx 16.49$ per unit time.", subtopicSlugs: S },
    { content: "A rectangular tank has base $2 \\times 3$ m$^2$ and is filled at $6$ m$^3$/min. Find the rate at which the water level rises.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $V = 6 h$ where $h$ is the depth.\n\n**Step 2 (1 mark):** Differentiate: $dV/dt = 6 \\cdot dh/dt$.\n\n**Step 3 (1 mark):** $6 = 6 dh/dt$, so $dh/dt = 1$ m/min.", subtopicSlugs: S },
    { content: "A spherical balloon has radius $r$ cm at time $t$ s, satisfying $r(t) = 3 + t$ cm. Find the rate of change of volume when $t = 2$ s.", marks: 4, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $V = \\tfrac{4}{3}\\pi r^3$, so $dV/dr = 4\\pi r^2$.\n\n**Step 2 (1 mark):** $dr/dt = 1$ cm/s.\n\n**Step 3 (1 mark):** $dV/dt = 4\\pi r^2 \\cdot 1$. At $t = 2$: $r = 5$.\n\n**Step 4 (1 mark):** $dV/dt = 4\\pi(25) = 100 \\pi$ cm$^3$/s.", subtopicSlugs: S },
    { content: "A particle's position is $s(t) = \\sin(2 t) - t$ metres. Find the velocity and acceleration at $t = 0$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $v(t) = 2\\cos(2 t) - 1$.\n\n**Step 2 (1 mark):** $v(0) = 2 - 1 = 1$ m/s.\n\n**Step 3 (1 mark):** $a(t) = -4\\sin(2 t)$, so $a(0) = 0$ m/s$^2$.", subtopicSlugs: S },
    { content: "The height of a ball is $h(t) = 20 t - 5 t^2$ m. At what time is the ball momentarily at rest, and what is its height then?", marks: 4, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Velocity $h'(t) = 20 - 10 t$.\n\n**Step 2 (1 mark):** Set to zero: $20 - 10 t = 0$.\n\n**Step 3 (1 mark):** $t = 2$ s.\n\n**Step 4 (1 mark):** $h(2) = 40 - 20 = 20$ m.", subtopicSlugs: S },
    { content: "An ice cube with side length $s$ cm is melting such that $s(t) = 4 - 0.5 t$ cm. Find $dV/dt$ when $t = 2$.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $V = s^3$, $dV/ds = 3 s^2$.\n\n**Step 2 (1 mark):** $ds/dt = -0.5$.\n\n**Step 3 (1 mark):** At $t = 2$: $s = 3$.\n\n**Step 4 (1 mark):** $dV/dt = 3(9)(-0.5) = -13.5$ cm$^3$/s.", subtopicSlugs: S },
    { content: "A cone has height equal to its radius. Water is pumped in at $5$ cm$^3$/min. Find the rate at which the water level rises when $h = 10$ cm.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $V = \\tfrac{1}{3}\\pi r^2 h$, with $r = h$: $V = \\tfrac{\\pi h^3}{3}$.\n\n**Step 2 (1 mark):** Differentiate: $dV/dt = \\pi h^2 dh/dt$.\n\n**Step 3 (1 mark):** At $h = 10$: $5 = \\pi(100) dh/dt$.\n\n**Step 4 (1 mark):** Solve: $dh/dt = \\dfrac{1}{20\\pi}$ cm/min.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "A rocket's height above the ground is $h(t) = 80 t - 5 t^2$ m for $0 \\leq t \\leq 16$ s.\n\n**a.** Find the velocity $v(t)$. (1 mark)\n\n**b.** Find the maximum height reached. (4 marks)\n\n**c.** Find the velocity at the instant the rocket reaches the ground. (3 marks)\n\n**d.** Find the acceleration at any time $t$. (1 mark)\n\n**e.** Sketch (describe) the graph of $h$ vs $t$. (2 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* Differentiate.\n\n$$v(t) = 80 - 10 t.$$\n\n**b. (4 marks)**\n\n*Step 1 (1 mark):* At max height, $v = 0$.\n\n*Step 2 (1 mark):* $80 - 10 t = 0$, so $t = 8$ s.\n\n*Step 3 (1 mark):* Evaluate $h(8) = 640 - 320$.\n\n*Step 4 (1 mark):* Max height $= 320$ m.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* At ground, $h(t) = 0$: $80 t - 5 t^2 = 0$, so $5 t(16 - t) = 0$.\n\n*Step 2 (1 mark):* Solutions: $t = 0$ (launch) or $t = 16$ (landing).\n\n*Step 3 (1 mark):* $v(16) = 80 - 160 = -80$ m/s (downward).\n\n**d. (1 mark)**\n\n*Step 1 (1 mark):* $a(t) = v'(t) = -10$ m/s$^2$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Parabola opening downward.\n\n*Step 2 (1 mark):* Starts at $(0, 0)$, peak at $(8, 320)$, ends at $(16, 0)$.", subtopicSlugs: S },
    { content: "Water is being pumped into a cylindrical tank of radius $2$ m at a constant rate of $4$ m$^3$/min.\n\n**a.** Let $h$ be the depth of water. Express $V$ in terms of $h$. (2 marks)\n\n**b.** Find $dV/dt$. (1 mark)\n\n**c.** Find $dh/dt$ using chain rule. (3 marks)\n\n**d.** How fast is the water level rising? (2 marks)\n\n**e.** How long until the depth reaches $5$ m, starting from empty? (2 marks)", marks: 10, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* $V = \\pi r^2 h$ with $r = 2$.\n\n*Step 2 (1 mark):* $V = 4 \\pi h$ m$^3$.\n\n**b. (1 mark)**\n\n*Step 1 (1 mark):* Given: $dV/dt = 4$ m$^3$/min.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Chain rule: $dV/dt = (dV/dh)(dh/dt)$.\n\n*Step 2 (1 mark):* Compute $dV/dh = 4\\pi$.\n\n*Step 3 (1 mark):* So $4 = 4\\pi \\cdot dh/dt$, giving $dh/dt = 1/\\pi$ m/min.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* From (c): $dh/dt = 1/\\pi$ m/min.\n\n*Step 2 (1 mark):* Numerically: $\\approx 0.318$ m/min.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* Time $= 5 / (1/\\pi) = 5 \\pi$ min.\n\n*Step 2 (1 mark):* Numerical: $\\approx 15.7$ min.", subtopicSlugs: S },
    { content: "A ladder of length $10$ m is leaning against a vertical wall. The base is sliding away from the wall at $2$ m/s.\n\n**a.** Let $x$ be the distance from the base to the wall and $y$ the height of the top. State the relationship between $x$ and $y$. (2 marks)\n\n**b.** Differentiate implicitly with respect to $t$. (2 marks)\n\n**c.** When $x = 6$ m, find $y$. (2 marks)\n\n**d.** Find how fast the top slides down when $x = 6$ m. (4 marks)\n\n**e.** Interpret the sign of $dy/dt$. (2 marks)", marks: 12, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Pythagoras.\n\n$$x^2 + y^2 = 100.$$\n\n*Step 2 (1 mark):* State relation.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Differentiate both sides.\n\n$$2 x \\dfrac{dx}{dt} + 2 y \\dfrac{dy}{dt} = 0.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$x \\dfrac{dx}{dt} + y \\dfrac{dy}{dt} = 0.$$\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $y^2 = 100 - 36 = 64$.\n\n*Step 2 (1 mark):* $y = 8$ m.\n\n**d. (4 marks)**\n\n*Step 1 (1 mark):* Given: $dx/dt = 2$, $x = 6$, $y = 8$.\n\n*Step 2 (1 mark):* Substitute into the implicit derivative.\n\n$$6 \\cdot 2 + 8 \\cdot \\dfrac{dy}{dt} = 0.$$\n\n*Step 3 (1 mark):* Solve.\n\n$$12 + 8 \\dfrac{dy}{dt} = 0 \\implies \\dfrac{dy}{dt} = -\\dfrac{12}{8} = -\\dfrac{3}{2}.$$\n\n*Step 4 (1 mark):* The top slides down at $3/2 = 1.5$ m/s.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* The sign is negative.\n\n*Step 2 (1 mark):* This indicates $y$ is decreasing — the top is moving downward.", subtopicSlugs: S },
    { content: "A population of bacteria grows according to $P(t) = 200 e^{0.1 t}$ where $t$ is in hours.\n\n**a.** Find the initial population. (1 mark)\n\n**b.** Find the rate of growth $P'(t)$. (2 marks)\n\n**c.** Show that $P'(t) = 0.1 P(t)$. (2 marks)\n\n**d.** Find the time at which the rate of growth equals $50$ bacteria/hour. (3 marks)\n\n**e.** Find the population at that time. (2 marks)\n\n**f.** Find the time at which the population doubles. (3 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $P(0) = 200$ bacteria.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* Apply the chain rule.\n\n$$P'(t) = 200 \\cdot 0.1 e^{0.1 t}.$$\n\n*Step 2 (1 mark):* Simplify.\n\n$$P'(t) = 20 e^{0.1 t}.$$\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* $P'(t) = 20 e^{0.1 t}$ and $P(t) = 200 e^{0.1 t}$.\n\n*Step 2 (1 mark):* So $P'(t) = 0.1 \\cdot 200 e^{0.1 t} = 0.1 P(t)$. ✓\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* Set $20 e^{0.1 t} = 50$.\n\n*Step 2 (1 mark):* $e^{0.1 t} = 2.5$.\n\n*Step 3 (1 mark):* $t = 10 \\ln 2.5 \\approx 9.16$ h.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* $P(t) = 0.1 \\cdot P = P'/0.1$, so $P = 50/0.1 = 500$.\n\n*Step 2 (1 mark):* Alternatively: $P(t) = 200 e^{0.1 t} = 200 \\cdot 2.5 = 500$ bacteria.\n\n**f. (3 marks)**\n\n*Step 1 (1 mark):* Set $P(t) = 400$.\n\n*Step 2 (1 mark):* $e^{0.1 t} = 2$.\n\n*Step 3 (1 mark):* $t = 10 \\ln 2 \\approx 6.93$ h.", subtopicSlugs: S },
    { content: "A spherical balloon is being inflated such that the radius increases at $0.5$ cm/s.\n\n**a.** State $dr/dt$. (1 mark)\n\n**b.** Express $V$ in terms of $r$ and find $dV/dr$. (2 marks)\n\n**c.** Find $dV/dt$ when $r = 4$ cm. (3 marks)\n\n**d.** Express $S$ (surface area) in terms of $r$ and find $dS/dt$ when $r = 4$ cm. (3 marks)\n\n**e.** After how many seconds will the volume reach $\\dfrac{4}{3}\\pi \\cdot 512$ cm$^3$? (Assume initial radius $0$.) (3 marks)\n\n**f.** How is $dS/dt$ related to $dr/dt$ in general? (2 marks)", marks: 14, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $dr/dt = 0.5$ cm/s.\n\n**b. (2 marks)**\n\n*Step 1 (1 mark):* $V = \\tfrac{4}{3}\\pi r^3$.\n\n*Step 2 (1 mark):* $dV/dr = 4\\pi r^2$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* Chain rule: $dV/dt = 4\\pi r^2 \\cdot dr/dt$.\n\n*Step 2 (1 mark):* Substitute $r = 4$, $dr/dt = 0.5$.\n\n$$dV/dt = 4\\pi(16)(0.5).$$\n\n*Step 3 (1 mark):* Simplify.\n\n$$dV/dt = 32\\pi \\text{ cm}^3/\\text{s}.$$\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $S = 4\\pi r^2$.\n\n*Step 2 (1 mark):* $dS/dt = 8\\pi r \\cdot dr/dt$. At $r = 4$, $dr/dt = 0.5$.\n\n*Step 3 (1 mark):* $dS/dt = 8\\pi(4)(0.5) = 16\\pi$ cm$^2$/s.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* $V = \\dfrac{4}{3}\\pi \\cdot 512$ requires $r^3 = 512$, so $r = 8$ cm.\n\n*Step 2 (1 mark):* $r(t) = 0 + 0.5 t$, so $0.5 t = 8$.\n\n*Step 3 (1 mark):* $t = 16$ s.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $dS/dt = 8\\pi r \\cdot dr/dt$.\n\n*Step 2 (1 mark):* So $dS/dt$ is proportional to $r \\cdot dr/dt$ — the rate grows linearly with $r$.", subtopicSlugs: S },
  ];
  writeQset(OUT("rates-of-change"), { mcq, shortAnswer, extendedResponse });
}

