// 10. STATIONARY POINTS AND CURVE SKETCHING
// ══════════════════════════════════════════════════════════════════════════
{
  const S = ["stationary-points-and-curve-sketching"];
  const mcq: MCQ[] = [
    { content: "A stationary point of $f(x)$ occurs where:", optionA: "$f(x) = 0$", optionB: "$f'(x) = 0$", optionC: "$f''(x) = 0$", optionD: "$f'(x) = f''(x)$", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** By definition, stationary means the instantaneous slope is $0$, i.e. $f'(x) = 0$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "If $f'(x) = 0$ and $f''(x) < 0$ at $x = a$, then $f$ has:", optionA: "local min", optionB: "local max", optionC: "inflection", optionD: "cannot tell", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** Second derivative test: $f''(a) < 0$ means concave down, so local maximum.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The stationary point of $f(x) = x^2 - 4 x + 5$ is at:", optionA: "$x = 0$", optionB: "$x = 1$", optionC: "$x = 2$", optionD: "$x = 4$", correctOption: "C", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $f'(x) = 2 x - 4 = 0$ gives $x = 2$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The function $f(x) = -x^2 + 4$ has a:", optionA: "local minimum at $x = 0$", optionB: "local maximum at $x = 0$", optionC: "point of inflection at $x = 0$", optionD: "no stationary points", correctOption: "B", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $f'(x) = -2 x = 0$ at $x = 0$. $f''(x) = -2 < 0$, so local max.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "A point of inflection occurs where $f''$ changes sign. For $f(x) = x^3$, the inflection is at:", optionA: "$x = 0$", optionB: "$x = 1$", optionC: "$x = -1$", optionD: "No inflection", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $f''(x) = 6 x$, which changes sign at $x = 0$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The function $f(x) = x^3 - 3 x^2$ has stationary points at:", optionA: "$x = 0$ and $x = 2$", optionB: "$x = 0$ and $x = 3$", optionC: "$x = 1$ and $x = 2$", optionD: "$x = 2$ only", correctOption: "A", marks: 1, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $f'(x) = 3 x^2 - 6 x = 3 x(x - 2)$. Zero at $x = 0$ and $x = 2$.\n\n**Answer: A**", subtopicSlugs: S },
    // Medium
    { content: "For $f(x) = x^3 - 3 x$, the local max and min are at:", optionA: "$x = 0, 1$", optionB: "$x = -1, 1$", optionC: "$x = 0, 3$", optionD: "$x = 1, 3$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = 3 x^2 - 3 = 0$ at $x = \\pm 1$. $f''(x) = 6 x$; at $x = -1$, $f'' < 0$ (max); at $x = 1$, $f'' > 0$ (min).\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The curve $f(x) = x^4$ has:", optionA: "local max at $x = 0$", optionB: "local min at $x = 0$", optionC: "inflection at $x = 0$", optionD: "no stationary points", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = 4 x^3 = 0$ at $x = 0$. $f'$ changes from negative to positive, so local min. (Note: $f''(0) = 0$, so second-derivative test is inconclusive.)\n\n**Answer: B**", subtopicSlugs: S },
    { content: `The graph of $y = x^3 - 6 x^2 + 9 x$ is shown.\n\n${graphImage((x) => x * x * x - 6 * x * x + 9 * x, { xMin: -1, xMax: 5, yMin: -1, yMax: 5, marks: [{ x: 1, y: 4, label: "max" }, { x: 3, y: 0, label: "min" }] }, "Cubic y=x^3-6x^2+9x")}\n\nThe local maximum occurs at:`, optionA: "$x = 0$", optionB: "$x = 1$", optionC: "$x = 3$", optionD: "$x = 5$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y' = 3 x^2 - 12 x + 9 = 3(x - 1)(x - 3)$. Sign analysis: max at $x = 1$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The second derivative of $f(x) = x^3 + 3 x^2$ at $x = -1$ is:", optionA: "$-6$", optionB: "$0$", optionC: "$6$", optionD: "$12$", correctOption: "B", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = 3 x^2 + 6 x$, $f''(x) = 6 x + 6$. At $x = -1$: $f''(-1) = 0$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "For $f(x) = 2 x^3 - 9 x^2 + 12 x$, the local max occurs at:", optionA: "$x = 1$", optionB: "$x = 2$", optionC: "$x = 3$", optionD: "$x = 0$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = 6 x^2 - 18 x + 12 = 6(x - 1)(x - 2)$. Sign: $+,-,+$. Max at $x = 1$, min at $x = 2$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The curve $y = e^x - x$ has a stationary point at:", optionA: "$x = 0$", optionB: "$x = 1$", optionC: "$x = -1$", optionD: "$x = e$", correctOption: "A", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y' = e^x - 1 = 0$ gives $e^x = 1$, so $x = 0$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: `Given the table of $f'(x)$ values:\n\n| $x$ | $0$ | $1$ | $2$ | $3$ | $4$ |\n|---|---|---|---|---|---|\n| $f'(x)$ | $-3$ | $0$ | $2$ | $0$ | $-5$ |\n\nThe function $f$ has a local maximum at:`, optionA: "$x = 1$", optionB: "$x = 2$", optionC: "$x = 3$", optionD: "$x = 4$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** Max occurs where $f'$ changes from positive to negative. At $x = 3$: $f'$ goes from $+2$ to $-5$. At $x = 1$: from $-3$ to $+2$ (that's a min).\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The function $y = x^3 - 3 x^2 + 3 x$ has:", optionA: "Local max only", optionB: "Local min only", optionC: "Point of inflection with zero slope", optionD: "No stationary points", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $y' = 3 x^2 - 6 x + 3 = 3(x - 1)^2 \\geq 0$. Stationary at $x = 1$ but $y'$ doesn't change sign — it's a horizontal inflection.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "For $f(x) = x^4 - 2 x^2$, the number of stationary points is:", optionA: "$1$", optionB: "$2$", optionC: "$3$", optionD: "$4$", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = 4 x^3 - 4 x = 4 x(x^2 - 1) = 4 x(x - 1)(x + 1)$. Three zeros: $x = 0, \\pm 1$.\n\n**Answer: C**", subtopicSlugs: S },
    { content: "The concavity of $f(x) = x^3$ is:", optionA: "Concave up everywhere", optionB: "Concave down everywhere", optionC: "Concave down then up (inflection at origin)", optionD: "Concave up then down", correctOption: "C", marks: 1, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f''(x) = 6 x$. Negative for $x < 0$ (concave down), positive for $x > 0$ (concave up). Inflection at $x = 0$.\n\n**Answer: C**", subtopicSlugs: S },
    // Hard
    { content: "The curve $y = x + \\dfrac{1}{x}$ (for $x > 0$) has a local minimum at:", optionA: "$x = 1$, $y = 2$", optionB: "$x = 1$, $y = 1$", optionC: "$x = 2$, $y = 5/2$", optionD: "$x = 1/2$, $y = 5/2$", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $y' = 1 - 1/x^2 = 0$ gives $x = 1$ (positive root). $y(1) = 1 + 1 = 2$. Local min at $(1, 2)$.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "The function $f(x) = x^3 - 3 x + 1$ has an inflection point at:", optionA: "$x = -1$", optionB: "$x = 0$", optionC: "$x = 1$", optionD: "$x = 3$", correctOption: "B", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $f''(x) = 6 x$, changes sign at $x = 0$.\n\n**Answer: B**", subtopicSlugs: S },
    { content: "The graph of $f$ has $f'(x) > 0$ for all $x$. The function is:", optionA: "Increasing only", optionB: "Decreasing only", optionC: "Has local extrema", optionD: "Constant", correctOption: "A", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Positive derivative means strictly increasing. No stationary points.\n\n**Answer: A**", subtopicSlugs: S },
    { content: "If $f(x) = a x^3 + b x^2 + c x + d$ has stationary points at $x = 1$ and $x = 3$, then:", optionA: "$3 a + 2 b + c = 0$ and $9 a + 2 b + c = 0$", optionB: "$3 a + b + c = 0$ and $27 a + 9 b + c = 0$", optionC: "$3 a + 2 b + c = 0$ and $27 a + 6 b + c = 0$", optionD: "None of the above", correctOption: "C", marks: 1, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $f'(x) = 3 a x^2 + 2 b x + c$. At $x = 1$: $3 a + 2 b + c = 0$. At $x = 3$: $27 a + 6 b + c = 0$.\n\n**Answer: C**", subtopicSlugs: S },
  ];
  const shortAnswer: FR[] = [
    { content: "Find the stationary points of $f(x) = x^2 - 6 x + 8$.", marks: 2, difficulty: "EASY", solutionContent: "**Step 1 (1 mark):** $f'(x) = 2 x - 6 = 0$.\n\n**Step 2 (1 mark):** $x = 3$, and $f(3) = 9 - 18 + 8 = -1$. Stationary point $(3, -1)$.", subtopicSlugs: S },
    { content: "For $f(x) = x^3 - 3 x + 2$, find the stationary points and classify them.", marks: 4, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = 3 x^2 - 3 = 0$, so $x = \\pm 1$.\n\n**Step 2 (1 mark):** $f''(x) = 6 x$.\n\n**Step 3 (1 mark):** At $x = -1$: $f'' = -6 < 0$, so local max. $f(-1) = -1 + 3 + 2 = 4$.\n\n**Step 4 (1 mark):** At $x = 1$: $f'' = 6 > 0$, so local min. $f(1) = 1 - 3 + 2 = 0$.", subtopicSlugs: S },
    { content: "Find all stationary points of $g(x) = x^4 - 4 x^3$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $g'(x) = 4 x^3 - 12 x^2 = 4 x^2(x - 3)$.\n\n**Step 2 (1 mark):** Set to zero: $x = 0$ (double) or $x = 3$.\n\n**Step 3 (1 mark):** Values: $g(0) = 0$, $g(3) = 81 - 108 = -27$.", subtopicSlugs: S },
    { content: "Determine the intervals on which $h(x) = x^3 - 3 x^2$ is increasing.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $h'(x) = 3 x^2 - 6 x = 3 x(x - 2)$.\n\n**Step 2 (1 mark):** $h' > 0$ when $x < 0$ or $x > 2$.\n\n**Step 3 (1 mark):** Increasing on $(-\\infty, 0)$ and $(2, \\infty)$.", subtopicSlugs: S },
    { content: "Find the $x$-values at which $f(x) = \\dfrac{1}{3} x^3 - x$ has a local max and local min.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = x^2 - 1 = 0$, so $x = \\pm 1$.\n\n**Step 2 (1 mark):** $f''(x) = 2 x$. At $x = -1$: $f'' < 0$, local max.\n\n**Step 3 (1 mark):** At $x = 1$: $f'' > 0$, local min.", subtopicSlugs: S },
    { content: "Find the point of inflection of $f(x) = x^3 - 6 x^2 + 5 x$.", marks: 3, difficulty: "MEDIUM", solutionContent: "**Step 1 (1 mark):** $f'(x) = 3 x^2 - 12 x + 5$.\n\n**Step 2 (1 mark):** $f''(x) = 6 x - 12 = 0$, so $x = 2$.\n\n**Step 3 (1 mark):** $f(2) = 8 - 24 + 10 = -6$. Inflection at $(2, -6)$.", subtopicSlugs: S },
    { content: "Sketch (describe key features of) $y = x^3 - 3 x^2$: intercepts, stationary points, concavity.", marks: 4, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** Intercepts: $y(0) = 0$, so $y$-intercept $(0, 0)$. $x^2(x - 3) = 0$, so $x$-intercepts at $x = 0, 3$.\n\n**Step 2 (1 mark):** $y' = 3 x^2 - 6 x = 3 x(x - 2) = 0$, stationary at $x = 0$, $x = 2$.\n\n**Step 3 (1 mark):** $y'' = 6 x - 6$. At $x = 0$: $y'' < 0$, local max $(0, 0)$. At $x = 2$: $y'' > 0$, local min $(2, -4)$.\n\n**Step 4 (1 mark):** Inflection at $x = 1$, $y = -2$. Concave down on $(-\\infty, 1)$, concave up on $(1, \\infty)$.", subtopicSlugs: S },
    { content: "Find the stationary points of $f(x) = x e^{-x}$ for $x \\in \\mathbb{R}$.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $f'(x) = e^{-x} - x e^{-x} = e^{-x}(1 - x)$.\n\n**Step 2 (1 mark):** Set to zero: $1 - x = 0$, so $x = 1$.\n\n**Step 3 (1 mark):** $f(1) = 1/e$. Stationary point $(1, 1/e)$.", subtopicSlugs: S },
    { content: "A cubic $f(x) = x^3 + a x$ has a local max and local min. Find the values of $a$ for which this is the case.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $f'(x) = 3 x^2 + a$.\n\n**Step 2 (1 mark):** For two stationary points, need $3 x^2 = -a$, so $a < 0$.\n\n**Step 3 (1 mark):** Thus $a < 0$.", subtopicSlugs: S },
    { content: "For $f(x) = x^3 - 6 x^2 + 9 x + 1$, find the intervals on which the function is concave up.", marks: 3, difficulty: "HARD", solutionContent: "**Step 1 (1 mark):** $f'(x) = 3 x^2 - 12 x + 9$, $f''(x) = 6 x - 12$.\n\n**Step 2 (1 mark):** Concave up means $f''(x) > 0$, i.e. $6 x - 12 > 0$.\n\n**Step 3 (1 mark):** $x > 2$, so $(2, \\infty)$.", subtopicSlugs: S },
  ];
  const extendedResponse: FR[] = [
    { content: "Consider $f(x) = x^3 - 9 x^2 + 24 x - 10$.\n\n**a.** Find $f'(x)$ and the stationary points. (3 marks)\n\n**b.** Classify each stationary point using the second derivative. (3 marks)\n\n**c.** Find the point of inflection. (2 marks)\n\n**d.** Identify intervals of increase and decrease. (3 marks)", marks: 11, difficulty: "HARD", solutionContent: "**a. (3 marks)**\n\n*Step 1 (1 mark):* Differentiate.\n\n$$f'(x) = 3 x^2 - 18 x + 24.$$\n\n*Step 2 (1 mark):* Set $f'(x) = 0$: divide by $3$.\n\n$$x^2 - 6 x + 8 = 0.$$\n\n*Step 3 (1 mark):* Factor: $(x - 2)(x - 4) = 0$, so $x = 2$ or $x = 4$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* $f''(x) = 6 x - 18$.\n\n*Step 2 (1 mark):* At $x = 2$: $f''(2) = -6 < 0$, so local max. $f(2) = 8 - 36 + 48 - 10 = 10$.\n\n*Step 3 (1 mark):* At $x = 4$: $f''(4) = 6 > 0$, so local min. $f(4) = 64 - 144 + 96 - 10 = 6$.\n\n**c. (2 marks)**\n\n*Step 1 (1 mark):* Set $f''(x) = 0$: $x = 3$.\n\n*Step 2 (1 mark):* $f(3) = 27 - 81 + 72 - 10 = 8$. Inflection at $(3, 8)$.\n\n**d. (3 marks)**\n\n*Step 1 (1 mark):* $f' > 0$ on $(-\\infty, 2)$: increasing.\n\n*Step 2 (1 mark):* $f' < 0$ on $(2, 4)$: decreasing.\n\n*Step 3 (1 mark):* $f' > 0$ on $(4, \\infty)$: increasing.", subtopicSlugs: S },
    { content: "Consider $g(x) = x^4 - 4 x^3 + 4 x^2$.\n\n**a.** Find $g'(x)$. (2 marks)\n\n**b.** Find all stationary points. (3 marks)\n\n**c.** Use $g''(x)$ to classify each. (3 marks)\n\n**d.** Find $g(x)$-intercepts. (2 marks)", marks: 10, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Differentiate term by term.\n\n*Step 2 (1 mark):* $g'(x) = 4 x^3 - 12 x^2 + 8 x$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Factor: $g'(x) = 4 x(x^2 - 3 x + 2)$.\n\n*Step 2 (1 mark):* Further: $g'(x) = 4 x(x - 1)(x - 2)$.\n\n*Step 3 (1 mark):* Stationary at $x = 0, 1, 2$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* $g''(x) = 12 x^2 - 24 x + 8$.\n\n*Step 2 (1 mark):* At $x = 0$: $g'' = 8 > 0$, local min. At $x = 1$: $g'' = -4 < 0$, local max. At $x = 2$: $g'' = 8 > 0$, local min.\n\n*Step 3 (1 mark):* Values: $g(0) = 0$, $g(1) = 1 - 4 + 4 = 1$, $g(2) = 16 - 32 + 16 = 0$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $g(x) = x^2(x - 2)^2 = 0$.\n\n*Step 2 (1 mark):* $x = 0$ or $x = 2$ (both double roots).", subtopicSlugs: S },
    { content: "Let $f(x) = 2 x^3 - 3 x^2 - 12 x + 5$.\n\n**a.** Find $f'(x)$ and set up the equation for stationary points. (2 marks)\n\n**b.** Solve to find the stationary points. (3 marks)\n\n**c.** Determine the nature of each stationary point. (3 marks)\n\n**d.** Find the $y$-intercept of the curve. (1 mark)\n\n**e.** Describe the end behaviour of $f$ as $x \\to \\pm \\infty$. (2 marks)\n\n**f.** Find the point of inflection. (2 marks)", marks: 13, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Differentiate.\n\n$$f'(x) = 6 x^2 - 6 x - 12.$$\n\n*Step 2 (1 mark):* Set to zero: divide by $6$.\n\n$$x^2 - x - 2 = 0.$$\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Factor.\n\n$$(x - 2)(x + 1) = 0.$$\n\n*Step 2 (1 mark):* Solutions.\n\n$$x = -1 \\text{ or } x = 2.$$\n\n*Step 3 (1 mark):* Compute $f(-1) = -2 - 3 + 12 + 5 = 12$; $f(2) = 16 - 12 - 24 + 5 = -15$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* $f''(x) = 12 x - 6$.\n\n*Step 2 (1 mark):* At $x = -1$: $f'' = -18 < 0$, local max $(-1, 12)$.\n\n*Step 3 (1 mark):* At $x = 2$: $f'' = 18 > 0$, local min $(2, -15)$.\n\n**d. (1 mark)**\n\n*Step 1 (1 mark):* $f(0) = 5$, so $y$-intercept $(0, 5)$.\n\n**e. (2 marks)**\n\n*Step 1 (1 mark):* As $x \\to \\infty$, $f(x) \\to \\infty$ (leading coefficient positive).\n\n*Step 2 (1 mark):* As $x \\to -\\infty$, $f(x) \\to -\\infty$.\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* $f''(x) = 0$ at $x = 1/2$.\n\n*Step 2 (1 mark):* $f(1/2) = 1/4 - 3/4 - 6 + 5 = -3/2$. Inflection at $(1/2, -3/2)$.", subtopicSlugs: S },
    { content: "Consider $h(x) = (x - 2)^2 (x + 1)$.\n\n**a.** Expand and write in standard form. (2 marks)\n\n**b.** Find $h'(x)$ and the stationary points. (4 marks)\n\n**c.** Classify each stationary point. (3 marks)\n\n**d.** Find $h(x)$-intercepts. (2 marks)\n\n**e.** Describe end behaviour of the curve. (1 mark)", marks: 12, difficulty: "HARD", solutionContent: "**a. (2 marks)**\n\n*Step 1 (1 mark):* Expand $(x - 2)^2 = x^2 - 4 x + 4$.\n\n*Step 2 (1 mark):* Multiply.\n\n$$h(x) = (x^2 - 4 x + 4)(x + 1) = x^3 - 3 x^2 + 0 \\cdot x + 4.$$\n\nRecompute: $(x^2 - 4x + 4)(x + 1) = x^3 + x^2 - 4x^2 - 4x + 4x + 4 = x^3 - 3 x^2 + 4$.\n\n**b. (4 marks)**\n\n*Step 1 (1 mark):* Differentiate.\n\n$$h'(x) = 3 x^2 - 6 x.$$\n\n*Step 2 (1 mark):* Factor.\n\n$$h'(x) = 3 x(x - 2).$$\n\n*Step 3 (1 mark):* Stationary at $x = 0$ or $x = 2$.\n\n*Step 4 (1 mark):* $h(0) = 4$; $h(2) = 0$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* $h''(x) = 6 x - 6$.\n\n*Step 2 (1 mark):* At $x = 0$: $h'' = -6 < 0$, local max $(0, 4)$.\n\n*Step 3 (1 mark):* At $x = 2$: $h'' = 6 > 0$, local min $(2, 0)$.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* Set $(x - 2)^2(x + 1) = 0$.\n\n*Step 2 (1 mark):* Roots: $x = 2$ (double), $x = -1$.\n\n**e. (1 mark)**\n\n*Step 1 (1 mark):* As $x \\to \\pm \\infty$: $h \\to \\pm \\infty$ (standard cubic shape).", subtopicSlugs: S },
    { content: "Let $f(x) = \\dfrac{x^3}{3} - 2 x^2 + 3 x$.\n\n**a.** Find $f'(x)$. (1 mark)\n\n**b.** Solve $f'(x) = 0$. (3 marks)\n\n**c.** Use $f''(x)$ to classify each stationary point. (3 marks)\n\n**d.** Find the point of inflection. (2 marks)\n\n**e.** Compute the values of $f$ at each stationary point and at the inflection. (3 marks)\n\n**f.** State the range of $f$ on $[0, 5]$. (2 marks)", marks: 14, difficulty: "HARD", solutionContent: "**a. (1 mark)**\n\n*Step 1 (1 mark):* $f'(x) = x^2 - 4 x + 3$.\n\n**b. (3 marks)**\n\n*Step 1 (1 mark):* Set $x^2 - 4 x + 3 = 0$.\n\n*Step 2 (1 mark):* Factor: $(x - 1)(x - 3) = 0$.\n\n*Step 3 (1 mark):* Solutions: $x = 1$ or $x = 3$.\n\n**c. (3 marks)**\n\n*Step 1 (1 mark):* $f''(x) = 2 x - 4$.\n\n*Step 2 (1 mark):* At $x = 1$: $f'' = -2 < 0$, local max.\n\n*Step 3 (1 mark):* At $x = 3$: $f'' = 2 > 0$, local min.\n\n**d. (2 marks)**\n\n*Step 1 (1 mark):* $f''(x) = 0$: $x = 2$.\n\n*Step 2 (1 mark):* $f(2) = 8/3 - 8 + 6 = 8/3 - 2 = 2/3$. Inflection $(2, 2/3)$.\n\n**e. (3 marks)**\n\n*Step 1 (1 mark):* $f(1) = 1/3 - 2 + 3 = 4/3$.\n\n*Step 2 (1 mark):* $f(3) = 9 - 18 + 9 = 0$.\n\n*Step 3 (1 mark):* $f(2) = 2/3$ (from part d).\n\n**f. (2 marks)**\n\n*Step 1 (1 mark):* Evaluate endpoints: $f(0) = 0$, $f(5) = 125/3 - 50 + 15 = 125/3 - 35 = 20/3$.\n\n*Step 2 (1 mark):* Min on $[0, 5]$: $0$ (at $x = 0$ or $x = 3$). Max: $20/3$ at $x = 5$. Range: $[0, 20/3]$.", subtopicSlugs: S },
  ];
  writeQset(OUT("stationary-points-and-curve-sketching"), { mcq, shortAnswer, extendedResponse });
}

